import React, { useState, useEffect, useRef } from 'react';
import { initializeApp } from 'firebase/app';
import { 
  getFirestore, collection, doc, setDoc, getDoc, 
  onSnapshot, updateDoc, deleteDoc, query 
} from 'firebase/firestore';
import { getAuth, signInAnonymously, onAuthStateChanged, signInWithCustomToken } from 'firebase/auth';
import { 
  Trash2, LogOut, Copy, Calculator, Users, ShieldCheck, Eraser, 
  Edit3, Zap, Store, Clock, Smartphone
} from 'lucide-react';

const firebaseConfig = JSON.parse(__firebase_config);
const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const db = getFirestore(app);
const appId = typeof __app_id !== 'undefined' ? __app_id : 'future-world-v38';

const getLocalDeviceId = () => {
  let id = localStorage.getItem('fw_device_id');
  if (!id) {
    id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
    localStorage.setItem('fw_device_id', id);
  }
  return id;
};

export default function App() {
  const [user, setUser] = useState(null);
  const [appState, setAppState] = useState('loading'); 
  const [isAdmin, setIsAdmin] = useState(false);
  const [activeTab, setActiveTab] = useState('calc'); 
  const [loginInput, setLoginInput] = useState('');
  const [allUsers, setAllUsers] = useState([]);
  const [adminSettings, setAdminSettings] = useState({ masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' });
  const [myDeviceId] = useState(getLocalDeviceId());

  useEffect(() => {
    document.title = adminSettings.shopName;
    const metaTheme = document.createElement('meta');
    metaTheme.name = "theme-color";
    metaTheme.content = "#000000";
    document.head.appendChild(metaTheme);
  }, [adminSettings.shopName]);

  useEffect(() => {
    const initAuth = async () => {
      if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) {
        await signInWithCustomToken(auth, __initial_auth_token);
      } else {
        await signInAnonymously(auth);
      }
    };
    initAuth();
    const unsubscribe = onAuthStateChanged(auth, setUser);
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    if (!user) return;
    const settingsRef = doc(db, 'artifacts', appId, 'public', 'settings');
    onSnapshot(settingsRef, (docSnap) => {
      if (docSnap.exists()) setAdminSettings(docSnap.data());
      else setDoc(settingsRef, { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' });
    });

    const usersRef = collection(db, 'artifacts', appId, 'public', 'data', 'users');
    const unsubUsers = onSnapshot(usersRef, (snap) => {
      setAllUsers(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
    setAppState('login');
    return () => unsubUsers();
  }, [user]);

  const handleLogin = async () => {
    const input = loginInput.trim().toUpperCase();
    if (input === adminSettings.masterPass.toUpperCase()) {
      setIsAdmin(true);
      setAppState('app');
      return;
    }
    const userEntry = allUsers.find(u => u.key === input);
    if (userEntry) {
      if (userEntry.deviceId && userEntry.deviceId !== myDeviceId) return;
      if (!userEntry.deviceId) {
        await updateDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', userEntry.id), { deviceId: myDeviceId });
      }
      setAppState('app');
    }
  };

  if (appState === 'loading') return <div className="h-screen bg-black flex items-center justify-center text-blue-500 font-bold">စောင့်ဆိုင်းပါ...</div>;

  if (appState === 'login') return (
    <div className="h-screen bg-black flex flex-col items-center justify-center p-6 text-white">
      <div className="w-full max-w-sm bg-slate-900 border border-slate-800 p-8 rounded-3xl text-center">
        <ShieldCheck className="mx-auto mb-4 text-blue-500" size={48} />
        <h1 className="text-xl font-black mb-2">{adminSettings.shopName}</h1>
        <input 
          type="text" placeholder="ကုဒ်ရိုက်ထည့်ပါ"
          className="w-full bg-slate-800 border border-slate-700 p-4 rounded-xl mb-4 text-center text-white outline-none font-black"
          value={loginInput} onChange={e => setLoginInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleLogin()}
        />
        <button onClick={handleLogin} className="w-full bg-blue-600 p-4 rounded-xl font-black">အကောင့်ဝင်မည်</button>
      </div>
    </div>
  );

  return (
    <div className="h-screen bg-black text-white flex flex-col overflow-hidden select-none">
      <header className="px-3 py-2 bg-slate-900 border-b border-slate-800 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2">
            <Store size={14} className="text-blue-500" />
            <span className="text-[10px] font-black uppercase text-slate-200">{adminSettings.shopName}</span>
        </div>
        <div className="flex gap-4">
          {isAdmin && (
            <button onClick={() => setActiveTab(activeTab === 'calc' ? 'admin' : 'calc')} className="text-blue-500">
              {activeTab === 'calc' ? <Users size={18}/> : <Calculator size={18}/>}
            </button>
          )}
          <button onClick={() => { setAppState('login'); setLoginInput(''); setIsAdmin(false); }} className="text-rose-600"><LogOut size={18}/></button>
        </div>
      </header>
      <main className="flex-1 overflow-hidden">
        {activeTab === 'admin' ? <AdminPanel allUsers={allUsers} db={db} appId={appId} /> : <CalculatorTool defaultShopName={adminSettings.shopName} />}
      </main>
    </div>
  );
}

function AdminPanel({ allUsers, db, appId }) {
  const [name, setName] = useState('');
  const createKey = async () => {
    if(!name) return;
    const key = `KEY-${Math.random().toString(36).substring(2,6).toUpperCase()}`;
    const userDocId = crypto.randomUUID();
    await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', userDocId), {
      id: userDocId, name, key, deviceId: null, createdAt: new Date().toISOString()
    });
    setName('');
  };
  return (
    <div className="p-4 flex flex-col h-full bg-slate-950 overflow-y-auto">
      <div className="bg-slate-900 p-4 rounded-2xl border border-slate-800 space-y-3 mb-6">
        <input placeholder="အမည်ရိုက်ပါ" className="w-full bg-slate-800 p-2 rounded-xl text-sm outline-none border border-slate-700" value={name} onChange={e=>setName(e.target.value)} />
        <button onClick={createKey} className="w-full bg-blue-600 py-2.5 rounded-xl font-black text-xs">ကုဒ် (KEY) ထုတ်မည်</button>
      </div>
      <div className="space-y-2">
        {allUsers.map(u => (
          <div key={u.id} className="bg-slate-900/50 p-3 rounded-xl border border-slate-800 flex justify-between items-center">
            <div><p className="text-blue-400 font-black text-xs">{u.name}</p><p className="text-[10px] font-mono text-slate-500">{u.key}</p></div>
            <button onClick={() => deleteDoc(doc(db, 'artifacts', appId, 'public', 'data', 'users', u.id))} className="text-rose-900 p-1"><Trash2 size={16}/></button>
          </div>
        ))}
      </div>
    </div>
  );
}

function CalculatorTool({ defaultShopName }) {
  const [numInput, setNumInput] = useState('');
  const [amtInput, setAmtInput] = useState('');
  const [dataList, setDataList] = useState([]);
  const [chips, setChips] = useState([]);
  const [isReverseMode, setIsReverseMode] = useState(false);
  const [personalShopName, setPersonalShopName] = useState(() => localStorage.getItem('fw_my_shop_name') || defaultShopName);
  const [isEditingName, setIsEditingName] = useState(false);

  const numRef = useRef(null);
  const amtRef = useRef(null);

  const addEntry = () => {
    let finalData = [];
    const nIn = numInput.trim();
    const aIn = amtInput.trim();
    if (!aIn) return;
    const baseAmt = parseFloat(aIn);
    if (isNaN(baseAmt)) return;

    if (aIn.includes('.') && nIn.length === 2 && !isNaN(nIn)) {
        const amtParts = aIn.split('.');
        const firstAmt = parseFloat(amtParts[0]);
        const secondAmt = parseFloat(amtParts[1]);
        const rNum = nIn[1] + nIn[0];
        if (!isNaN(firstAmt)) finalData.push({ id: Math.random(), n: nIn, a: firstAmt });
        if (!isNaN(secondAmt) && nIn !== rNum) finalData.push({ id: Math.random(), n: rNum, a: secondAmt });
    } else {
        const actualAmt = isReverseMode ? (baseAmt / 2) : baseAmt;
        let nums = chips.length > 0 ? [...chips] : (nIn.includes('.') ? nIn.split('.') : [nIn]);
        nums.forEach(n => {
            const cleanN = n.toString().trim().padStart(2, '0');
            if (cleanN && cleanN.length <= 2) finalData.push({ id: Math.random(), n: cleanN, a: actualAmt });
        });
    }

    if (finalData.length > 0) {
        setDataList([...finalData, ...dataList]);
        setChips([]); setNumInput(''); setAmtInput(''); setIsReverseMode(false);
        numRef.current?.focus();
    }
  };

  const applyMode = (type) => {
    let res = [];
    const rawValue = numInput.trim();
    const items = rawValue.includes('.') ? rawValue.split('.') : [rawValue];
    const validNums = items.map(i => i.trim()).filter(i => i !== '');
    const autoMods = ['ပါဝါ','နက္ခတ်','ညီအစ်ကို','ကိုးညီ','ပူး','စုံစုံ','မမ','စုံမ','မစုံ','စုံပူး','မပူး'];
    if (validNums.length === 0 && !autoMods.includes(type)) { numRef.current?.focus(); return; }
    setIsReverseMode(type === 'အာ');

    switch(type) {
      case 'အာ': validNums.forEach(nStr => { const n = nStr.padStart(2, '0'); res.push(n); const reversed = n[1] + n[0]; if (n !== reversed) res.push(reversed); }); break;
      case 'ခွေ': validNums.forEach(str => { const digits = str.split(''); for(let i=0; i<digits.length; i++) for(let j=0; j<digits.length; j++) if (i !== j) res.push(digits[i] + digits[j]); }); break;
      case 'ပူး': if (validNums.length > 0) validNums.forEach(d => res.push(d.charAt(0) + d.charAt(0))); else res = ['00','11','22','33','44','55','66','77','88','99']; break;
      case 'ပါဝါ': res = ['05','16','27','38','49','50','61','72','83','94']; break;
      case 'နက္ခတ်': res = ['07','18','24','35','69','70','81','42','53','96']; break;
      case 'ညီအစ်ကို': res = ['01','12','23','34','45','56','67','78','89','90','10','21','32','43','54','65','76','87','98','09']; break;
      case 'ကိုးညီ': res = ['18','27','36','45','81','72','63','54']; break;
      case 'စုံစုံ': for(let i=0; i<=8; i+=2) for(let j=0; j<=8; j+=2) if(i !== j) res.push(`${i}${j}`); break;
      case 'မမ': for(let i=1; i<=9; i+=2) for(let j=1; j<=9; j+=2) if(i !== j) res.push(`${i}${j}`); break;
      case 'စုံမ': for(let i=0; i<=8; i+=2) for(let j=1; j<=9; j+=2) res.push(`${i}${j}`); break;
      case 'မစုံ': for(let i=1; i<=9; i+=2) for(let j=0; j<=8; j+=2) res.push(`${i}${j}`); break;
      case 'စုံပူး': res = ['00','22','44','66','88']; break;
      case 'မပူး': res = ['11','33','55','77','99']; break;
      case 'ဘရိတ်': const b = parseInt(validNums[0]); for(let i=0; i<=9; i++) for(let j=0; j<=9; j++) if((i+j)%10 === b) res.push(`${i}${j}`); break;
      case 'ထိပ်': validNums.forEach(d => { for(let i=0; i<=9; i++) res.push(d.charAt(0)+i); }); break;
      case 'ပိတ်': validNums.forEach(d => { for(let i=0; i<=9; i++) res.push(i+d.charAt(0)); }); break;
      case 'ဝမ်း': for(let i=0; i<validNums.length; i++) for(let j=0; j<validNums.length; j++) res.push(validNums[i].charAt(0)+validNums[j].charAt(0)); break;
    }
    setChips([...new Set([...chips, ...res])]); setNumInput(''); setTimeout(() => amtRef.current?.focus(), 50);
  };

  const copyAndClear = () => {
    if (dataList.length === 0) return;
    const now = new Date();
    const dateStr = now.toLocaleDateString('en-GB'); 
    const timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    let text = `--- ${personalShopName} ---\nနေ့စွဲ - ${dateStr} (${timeStr})\n\n`;
    dataList.forEach(item => { text += `${item.n} = ${item.a}\n`; });
    text += `----------\nစုစုပေါင်း: (${dataList.length}) ကွက် - ${dataList.reduce((s,i) => s + i.a, 0)} ကျပ်`;
    const el = document.createElement('textarea'); el.value = text; document.body.appendChild(el); el.select(); document.execCommand('copy'); document.body.removeChild(el);
    setDataList([]); setChips([]); setNumInput(''); setAmtInput(''); numRef.current?.focus();
  };

  const modButtons = ['အာ','ခွေ','ပူး','ပါဝါ','နက္ခတ်','ညီအစ်ကို','ဘရိတ်','ထိပ်','ပိတ်','ဝမ်း','ကိုးညီ','စုံစုံ','မမ','စုံမ','မစုံ','စုံပူး','မပူး'];

  return (
    <div className="h-full flex flex-col bg-black">
      {/* Input Section - Optimized Size */}
      <div className="bg-slate-900 px-3 pt-2 pb-2 border-b border-slate-800 shrink-0">
        <div className="flex justify-between items-center mb-1.5 px-1">
            <button onClick={() => setIsEditingName(true)} className="flex items-center gap-1">
                <span className="text-slate-500 text-[9px] font-black uppercase">{personalShopName}</span>
                <Edit3 size={10} className="text-slate-800" />
            </button>
            {isEditingName && (
                <input 
                    autoFocus className="absolute left-3 bg-slate-800 border border-blue-500 rounded px-2 py-0.5 text-[10px] outline-none z-30"
                    value={personalShopName} onChange={e => setPersonalShopName(e.target.value)} onBlur={() => { setIsEditingName(false); localStorage.setItem('fw_my_shop_name', personalShopName); }}
                />
            )}
        </div>

        <div className="flex gap-2 mb-2">
            <div className="flex-1 space-y-1.5">
                <input 
                    ref={numRef} type="text" inputMode="decimal" placeholder="ဂဏန်း" 
                    className="w-full bg-slate-800/80 border border-slate-700 py-2 rounded-lg font-black text-center text-base outline-none text-white focus:border-blue-500"
                    value={numInput} onChange={e => setNumInput(e.target.value)}
                />
                <input 
                    ref={amtRef} type="text" inputMode="decimal" placeholder={isReverseMode ? "ခွဲမည်" : "ငွေပမာဏ"} 
                    className={`w-full bg-slate-800/80 border py-2 rounded-lg font-black text-center text-base outline-none text-white focus:border-blue-500 ${isReverseMode ? 'border-blue-500 bg-blue-900/10' : 'border-slate-700'}`}
                    value={amtInput} onChange={e => setAmtInput(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && addEntry()}
                />
            </div>
            <button 
                onClick={() => { setDataList(dataList.slice(1)); numRef.current?.focus(); }} 
                className="w-14 bg-slate-800 text-slate-500 rounded-lg border border-slate-700 flex flex-col items-center justify-center active:bg-rose-900/20 active:text-rose-500"
            >
                <Eraser size={20} className="mb-0.5"/>
                <span className="text-[8px] font-black uppercase">ပြန်ဖျက်</span>
            </button>
        </div>

        <div className="grid grid-cols-6 gap-1">
          {modButtons.map(k => (
            <button key={k} onClick={() => applyMode(k)} className={`py-1.5 rounded-md font-black text-[9px] border ${k==='အာ' && isReverseMode ? 'bg-blue-600 border-blue-400 text-white' : 'bg-slate-800/50 text-slate-500 border-slate-700/50'}`}>{k}</button>
          ))}
        </div>
      </div>

      <div className="bg-slate-950 px-3 py-1 flex flex-wrap gap-1 min-h-[16px] items-center border-b border-slate-900 shrink-0">
        {chips.map((c, i) => <span key={i} className="text-blue-500 text-[8px] font-black border border-blue-500/10 px-1 rounded bg-blue-500/5">{c}</span>)}
        {chips.length > 0 && <button onClick={() => { setChips([]); setIsReverseMode(false); }} className="text-[7px] text-slate-700 ml-auto font-black uppercase">ရှင်းမည်</button>}
      </div>

      <div className="flex-1 overflow-y-auto px-3 py-3 space-y-1.5 bg-black pb-28">
        {dataList.length === 0 ? (
          <div className="h-full flex items-center justify-center opacity-10 flex-col gap-2">
            <Calculator size={36} />
            <p className="text-[10px] font-black tracking-widest uppercase italic text-center">စာရင်းမရှိသေးပါ</p>
          </div>
        ) : (
          dataList.map(item => (
            <div key={item.id} className="flex justify-between items-center bg-slate-900/30 border border-slate-800/10 px-4 py-2 rounded-xl">
              <span className="text-lg font-black text-white">{item.n}</span>
              <div className="flex items-center gap-4">
                <span className="text-base font-black text-blue-500">{item.a.toLocaleString()}</span>
                <button onClick={() => setDataList(dataList.filter(i => i.id !== item.id))} className="text-slate-800 p-1"><Trash2 size={16}/></button>
              </div>
            </div>
          ))
        )}
      </div>

      {dataList.length > 0 && (
        <div className="fixed bottom-0 left-0 right-0 bg-slate-900/95 backdrop-blur-md p-3 flex items-center gap-2 border-t border-slate-800 shadow-2xl z-40 pb-5">
          <button onClick={() => setDataList([])} className="w-12 bg-rose-950/10 text-rose-800 rounded-xl border border-rose-900/20 h-11 flex items-center justify-center active:bg-rose-900/40"><Trash2 size={20}/></button>
          <div className="px-3 min-w-[80px] border-r border-slate-800">
            <p className="text-[14px] font-black text-blue-500 leading-none">{dataList.reduce((s,i) => s + i.a, 0).toLocaleString()}</p>
            <p className="text-[8px] text-slate-500 font-black mt-1 uppercase tracking-tighter">စုစုပေါင်းပမာဏ</p>
          </div>
          <button onClick={copyAndClear} className="flex-1 bg-white text-black h-11 rounded-xl font-black text-xs flex items-center justify-center gap-2 active:scale-95 shadow-lg uppercase">
            <Copy size={14}/> ကူးယူပြီး အကုန်ရှင်းမည်
          </button>
        </div>
      )}
    </div>
  );
}

