{
  "name": "Future World Calculator",
  "description": "A specialized calculator tool with user management for shops, built with a dark, modern UI. Features role-based access for admins and users, real-time data synchronization, and tools for quick number generation and calculation."
}

import '@angular/compiler';
import { bootstrapApplication } from '@angular/platform-browser';
import { provideZonelessChangeDetection } from '@angular/core';

import { AppComponent } from './src/app.component';

bootstrapApplication(AppComponent, {
  providers: [
    provideZonelessChangeDetection(),
  ],
}).catch(err => console.error(err));

import { Component, ChangeDetectionStrategy, signal, inject, effect, untracked } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FirebaseService, AdminSettings, UserData } from './services/firebase.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'loading' | 'login' | 'app';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
  ],
})
export class AppComponent {
  private firebaseService = inject(FirebaseService);
  private titleService = inject(Title);

  appState = signal<AppState>('loading');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');

  adminSettings = this.firebaseService.adminSettings;
  allUsers = this.firebaseService.allUsers;
  myDeviceId = this.firebaseService.getLocalDeviceId();

  constructor() {
    this.firebaseService.initialize();

    effect(() => {
      const user = this.firebaseService.user();
      if (user) {
        untracked(() => {
            this.appState.set('login');
        });
      }
    });

    effect(() => {
        const settings = this.adminSettings();
        if (settings?.shopName) {
            this.titleService.setTitle(settings.shopName);
        }
    });
  }

  async handleLogin(loginInput: string) {
    const settings = this.adminSettings();
    if (!settings) return;

    const input = loginInput.trim().toUpperCase();
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      this.appState.set('app');
      this.activeTab.set('calc');
      return;
    }

    const users = this.allUsers();
    const userEntry = users.find(u => u.key === input);
    if (userEntry) {
      if (userEntry.deviceId && userEntry.deviceId !== this.myDeviceId) {
        // Potentially show an error message
        console.error("Device ID does not match.");
        return;
      }
      if (!userEntry.deviceId) {
        await this.firebaseService.updateUserDevice(userEntry.id, this.myDeviceId);
      }
      this.isAdmin.set(false);
      this.appState.set('app');
      this.activeTab.set('calc');
    }
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }
}

@switch (appState()) {
  @case ('loading') {
    <div class="h-screen bg-black flex items-center justify-center text-blue-500 font-bold">စောင့်ဆိုင်းပါ...</div>
  }
  @case ('login') {
    <app-login [shopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'" (loginAttempt)="handleLogin($event)"></app-login>
  }
  @case ('app') {
    <div class="h-screen bg-black text-white flex flex-col overflow-hidden select-none">
      <header class="px-3 py-2 bg-slate-900 border-b border-slate-800 flex justify-between items-center shrink-0">
        <div class="flex items-center gap-2">
          <app-store-icon class="text-blue-500"></app-store-icon>
          <span class="text-[10px] font-black uppercase text-slate-200">{{ adminSettings()?.shopName }}</span>
        </div>
        <div class="flex gap-4">
          @if (isAdmin()) {
            <button (click)="toggleTab()" class="text-blue-500">
              @if (activeTab() === 'calc') {
                <app-users-icon></app-users-icon>
              } @else {
                <app-calculator-icon></app-calculator-icon>
              }
            </button>
          }
          <button (click)="handleLogout()" class="text-rose-600">
            <app-logout-icon></app-logout-icon>
          </button>
        </div>
      </header>
      <main class="flex-1 overflow-hidden">
        @if (activeTab() === 'admin' && isAdmin()) {
          <app-admin-panel></app-admin-panel>
        } @else {
          <app-calculator [defaultShopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'"></app-calculator>
        }
      </main>
    </div>
  }
}

import { Injectable, signal } from '@angular/core';
import { initializeApp, FirebaseApp } from 'firebase/app';
import { 
  getFirestore, collection, doc, setDoc, onSnapshot, updateDoc, 
  deleteDoc, Firestore
} from 'firebase/firestore';
import { 
  getAuth, signInAnonymously, onAuthStateChanged, User, 
  signInWithCustomToken, Auth
} from 'firebase/auth';

// Declare global variables provided by the Applet environment
declare const __firebase_config: string;
declare const __app_id: string;
declare const __initial_auth_token: string;

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name: string;
  key: string;
  deviceId: string | null;
  createdAt: string;
}

@Injectable({
  providedIn: 'root',
})
export class FirebaseService {
  private app: FirebaseApp;
  private auth: Auth;
  private db: Firestore;
  private appId: string;

  user = signal<User | null>(null);
  adminSettings = signal<AdminSettings | null>(null);
  allUsers = signal<UserData[]>([]);

  constructor() {
    const firebaseConfig = JSON.parse(__firebase_config);
    this.app = initializeApp(firebaseConfig);
    this.auth = getAuth(this.app);
    this.db = getFirestore(this.app);
    this.appId = typeof __app_id !== 'undefined' ? __app_id : 'future-world-v38';
  }

  initialize() {
    this.initAuth();
    onAuthStateChanged(this.auth, (firebaseUser) => {
      this.user.set(firebaseUser);
      if (firebaseUser) {
        this.subscribeToData();
      }
    });
  }

  private async initAuth() {
    if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) {
      await signInWithCustomToken(this.auth, __initial_auth_token);
    } else {
      await signInAnonymously(this.auth);
    }
  }

  private subscribeToData() {
    // Subscribe to settings
    const settingsRef = doc(this.db, 'artifacts', this.appId, 'public', 'settings');
    onSnapshot(settingsRef, (docSnap) => {
      if (docSnap.exists()) {
        this.adminSettings.set(docSnap.data() as AdminSettings);
      } else {
        const defaultSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
        setDoc(settingsRef, defaultSettings);
        this.adminSettings.set(defaultSettings);
      }
    });

    // Subscribe to users
    const usersRef = collection(this.db, 'artifacts', this.appId, 'public', 'data', 'users');
    onSnapshot(usersRef, (snap) => {
      const usersList = snap.docs.map(d => ({ id: d.id, ...d.data() } as UserData));
      this.allUsers.set(usersList);
    });
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }

  async updateUserDevice(userId: string, deviceId: string): Promise<void> {
    const userDocRef = doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId);
    await updateDoc(userDocRef, { deviceId });
  }

  async createNewUser(name: string): Promise<void> {
    if (!name) return;
    const key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
    const userDocId = crypto.randomUUID();
    const newUser: UserData = {
      id: userDocId,
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString()
    };
    await setDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userDocId), newUser);
  }

  async deleteUser(userId: string): Promise<void> {
    await deleteDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId));
  }
}

