@Injectable({
  providedIn: 'root',
})
export class FirebaseService {
  private app: FirebaseApp | undefined;
  private auth: Auth | undefined;
  private db: Firestore | undefined;
  private appId: string;

  isInitialized = false;

  user = signal<User | null>(null);
  adminSettings = signal<AdminSettings | null>(null);
  allUsers = signal<UserData[]>([]);

  constructor() {
    this.appId = typeof __app_id !== 'undefined' ? __app_id : 'future-world-v38';
    let firebaseConfig;

    if (typeof __firebase_config !== 'undefined' && __firebase_config) {
      try {
        firebaseConfig = JSON.parse(__firebase_config);
        if (!firebaseConfig.apiKey) {
          throw new Error("Firebase config is missing apiKey.");
        }
        this.app = initializeApp(firebaseConfig);
        this.auth = getAuth(this.app);
        this.db = getFirestore(this.app);
        this.isInitialized = true;
      } catch (e) {
        console.error('Failed to initialize Firebase:', e);
        this.isInitialized = false;
      }
    } else {
      console.error('Firebase configuration (__firebase_config) is missing.');
      this.isInitialized = false;
    }
  }

  initialize() {
    if (!this.auth) return;

    this.initAuth();
    onAuthStateChanged(this.auth, (firebaseUser) => {
      this.user.set(firebaseUser);
      if (firebaseUser) {
        this.subscribeToData();
      }
    });
  }

  private async initAuth() {
    if (!this.auth) return;
    if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) {
      await signInWithCustomToken(this.auth, __initial_auth_token);
    } else {
      await signInAnonymously(this.auth);
    }
  }

  private subscribeToData() {
    if (!this.db) return;
    // Subscribe to settings
    const settingsRef = doc(this.db, 'artifacts', this.appId, 'public', 'settings');
    onSnapshot(settingsRef, (docSnap) => {
      if (docSnap.exists()) {
        this.adminSettings.set(docSnap.data() as AdminSettings);
      } else {
        const defaultSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
        setDoc(settingsRef, defaultSettings);
        this.adminSettings.set(defaultSettings);
      }
    });

    // Subscribe to users
    const usersRef = collection(this.db, 'artifacts', this.appId, 'public', 'data', 'users');
    onSnapshot(usersRef, (snap) => {
      const usersList = snap.docs.map(d => ({ id: d.id, ...d.data() } as UserData));
      this.allUsers.set(usersList);
    });
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
