  async updateUserDevice(userId: string, deviceId: string): Promise<void> {
    if (!this.db) return;
    const userDocRef = doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId);
    await updateDoc(userDocRef, { deviceId });
  }

  async createNewUser(name: string): Promise<void> {
    if (!this.db || !name) return;
    const key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
    const userDocId = crypto.randomUUID();
    const newUser: UserData = {
      id: userDocId,
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString()
    };
    await setDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userDocId), newUser);
