  totalCount = computed(() => this.dataList().length);

  modButtons = ['အာ','ခွေ','ပူး','ပါဝါ','နက္ခတ်','ညီအစ်ကို','ဘရိတ်','ထိပ်','ပိတ်','ဝမ်း','ကိုးညီ','စုံစုံ','မမ','စုံမ','မစုံ','စုံပူး','မပူး'];

  constructor() {
