// These are expected to be provided globally in the execution environment.
declare const __firebase_config: string;
declare const __app_id: string;

export type FirebaseStatus = 'initializing' | 'ready' | 'error';

@Injectable({
  providedIn: 'root',
})
export class FirebaseService {
  app!: FirebaseApp;
  db!: Firestore;
  appId: string;
  status = signal<FirebaseStatus>('initializing');

  constructor() {
    this.appId = typeof __app_id !== 'undefined' ? __app_id : 'future-world-v38';

    try {
      const configStr = typeof __firebase_config !== 'undefined' ? __firebase_config : null;
      if (!configStr) {
        throw new Error('Firebase configuration (__firebase_config) is missing.');
      }

      const firebaseConfig = JSON.parse(configStr);
      if (!firebaseConfig || !firebaseConfig.apiKey) {
        throw new Error('Firebase configuration is invalid or missing apiKey.');
      }

      this.app = initializeApp(firebaseConfig);
      this.db = getFirestore(this.app);
      this.status.set('ready');
    } catch (error) {
      console.error('Firebase initialization failed:', error);
      this.status.set('error');
    }
  }
}

