  auth!: Auth;
  appId: string;
  status = signal<FirebaseStatus>('initializing');
  currentUser = signal<User | null>(null);

  constructor() {
    this.appId = typeof __app_id !== 'undefined' ? __app_id : 'future-world-v38';
    this.initializeFirebase();
  }

  private async initializeFirebase(): Promise<void> {
    try {
      const configStr = typeof __firebase_config !== 'undefined' ? __firebase_config : null;
      if (!configStr) {
        console.error('Firebase configuration (__firebase_config) is missing.');
        this.status.set('error');
        return;
      }

      const firebaseConfig = JSON.parse(configStr);
      if (!firebaseConfig || !firebaseConfig.apiKey) {
        console.error('Firebase configuration is invalid or missing apiKey.');
        this.status.set('error');
        return;
      }

      this.app = initializeApp(firebaseConfig);
      this.db = getFirestore(this.app);
      this.auth = getAuth(this.app);

      onAuthStateChanged(this.auth, (user) => {
        this.currentUser.set(user);
      });

      await signInAnonymously(this.auth);

      this.status.set('ready');

    } catch (error) {
      console.error('Firebase initialization failed:', error);
      this.status.set('error');
    }
  }
}

import { Injectable, signal, inject, OnDestroy, effect } from '@angular/core';
import { FirebaseService } from './firebase.service';
import { doc, onSnapshot, collection, setDoc, updateDoc, deleteDoc, Unsubscribe } from 'firebase/firestore';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name: string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

@Injectable({
  providedIn: 'root',
})
export class DataService implements OnDestroy {
  private firebaseService = inject(FirebaseService);

  adminSettings = signal<AdminSettings | null>(null);
  allUsers = signal<UserData[]>([]);
  isInitialized = signal(false);

  private settingsUnsub: Unsubscribe | undefined;
  private usersUnsub: Unsubscribe | undefined;
  private settingsLoaded = false;
  private usersLoaded = false;
  private listenersAttached = false;

  constructor() {
    effect(() => {
      const status = this.firebaseService.status();
      const user = this.firebaseService.currentUser();

      if (status === 'ready' && user && !this.listenersAttached) {
        this.listenersAttached = true;
        this.listenForAdminSettings();
        this.listenForUsers();
      } else if (status === 'error') {
        this.adminSettings.set(null);
        this.allUsers.set([]);
        this.settingsLoaded = true;
        this.usersLoaded = true;
        this.checkInitialized();
      }
    });
  }

  ngOnDestroy() {
    this.settingsUnsub?.();
    this.usersUnsub?.();
  }

  private checkInitialized() {
    if (this.settingsLoaded && this.usersLoaded && !this.isInitialized()) {
      this.isInitialized.set(true);
    }
  }

  private listenForAdminSettings() {
    const settingsRef = doc(this.firebaseService.db, 'artifacts', this.firebaseService.appId, 'public', 'settings');
    this.settingsUnsub = onSnapshot(settingsRef, (docSnap) => {
      if (docSnap.exists()) {
        this.adminSettings.set(docSnap.data() as AdminSettings);
      } else {
        const defaultSettings: AdminSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
        setDoc(settingsRef, defaultSettings).catch(e => console.error("Failed to set default settings", e));
        this.adminSettings.set(defaultSettings);
      }
      this.settingsLoaded = true;
      this.checkInitialized();
    }, (error) => {
      console.error("Error fetching admin settings:", error);
      const defaultSettings: AdminSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
      this.adminSettings.set(defaultSettings);
      this.settingsLoaded = true;
      this.checkInitialized();
    });
  }

  private listenForUsers() {
    const usersRef = collection(this.firebaseService.db, 'artifacts', this.firebaseService.appId, 'public', 'data', 'users');
    this.usersUnsub = onSnapshot(usersRef, (snap) => {
      const users = snap.docs.map(d => ({ id: d.id, ...d.data() } as UserData));
      this.allUsers.set(users);
      this.usersLoaded = true;
      this.checkInitialized();
    }, (error) => {
       console.error("Error fetching users:", error);
       this.allUsers.set([]);
       this.usersLoaded = true;
       this.checkInitialized();
    });
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }

  async updateUserDevice(userId: string, deviceId: string): Promise<void> {
    const userDocRef = doc(this.firebaseService.db, 'artifacts', this.firebaseService.appId, 'public', 'data', 'users', userId);
    try {
      await updateDoc(userDocRef, { deviceId: deviceId });
    } catch (e) {
      console.error('Failed to update user device in Firestore', e);
    }
  }

  async createNewUser(name: string, expiresAt: string | null): Promise<void> {
    if (!name) return;

    let key: string;
    let isUnique = false;
    const existingKeys = new Set(this.allUsers().map(u => u.key));

    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!existingKeys.has(key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const userDocId = crypto.randomUUID();
    const newUser: Omit<UserData, 'id'> = {
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString(),
      expiresAt,
    };

    const userDocRef = doc(this.firebaseService.db, 'artifacts', this.firebaseService.appId, 'public', 'data', 'users', userDocId);
    try {
      await setDoc(userDocRef, { ...newUser, id: userDocId });
    } catch (e) {
      console.error('Failed to create new user in Firestore', e);
    }
  }

  async deleteUser(userId: string): Promise<void> {
    const userDocRef = doc(this.firebaseService.db, 'artifacts', this.firebaseService.appId, 'public', 'data', 'users', userId);
    try {
      await deleteDoc(userDocRef);
    } catch (e) {
      console.error('Failed to delete user in Firestore', e);
    }
  }
}

import { Component, ChangeDetectionStrategy, signal, inject, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService } from './services/data.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'loading' | 'login' | 'app';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
  ],
})
export class AppComponent {
  private dataService = inject(DataService);
  private titleService = inject(Title);

  appState = signal<AppState>('loading');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  allUsers = this.dataService.allUsers;
  myDeviceId = this.dataService.getLocalDeviceId();
  isDataReady = this.dataService.isInitialized;

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });

    effect(() => {
      if (this.isDataReady() && this.appState() === 'loading') {
        this.appState.set('login');
      }
    });
  }

  handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const settings = this.adminSettings();
    if (!settings) {
        this.loginError.set('Application settings not found.');
        this.isLoggingIn.set(false);
        return;
    }

    const input = loginInput.trim().toUpperCase();

    // Admin Login
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    // User Login
    const users = this.allUsers();
    const userEntry = users.find(u => u.key === input);

    if (!userEntry) {
      this.loginError.set('ကုဒ်မှားနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check for expiration
    if (userEntry.expiresAt && new Date(userEntry.expiresAt) < new Date()) {
      this.loginError.set('Key သက်တမ်းကုန်နေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check device lock
    if (userEntry.deviceId && userEntry.deviceId !== this.myDeviceId) {
      this.loginError.set('Key ကိုအခြားဖုန်းတွင်အသုံးပြုနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Lock device if not already locked
    if (!userEntry.deviceId) {
      this.dataService.updateUserDevice(userEntry.id, this.myDeviceId);
    }

    // Success
    this.isAdmin.set(false);
    this.appState.set('app');
    this.activeTab.set('calc');
    this.isLoggingIn.set(false);
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(null);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  clearLoginError() {
      this.loginError.set(null);
  }
}

@switch (appState()) {
  @case ('loading') {
    <div class="h-screen bg-black flex items-center justify-center text-blue-500 font-bold">စောင့်ဆိုင်းပါ...</div>
  }
  @case ('login') {
    <app-login 
      [shopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'" 
      [loginError]="loginError()"
      [isLoggingIn]="isLoggingIn()"
      (loginAttempt)="handleLogin($event)"
      (inputChange)="clearLoginError()">
    </app-login>
  }
  @case ('app') {
    <div class="h-screen bg-black text-white flex flex-col overflow-hidden select-none">
      <header class="px-3 py-2 bg-slate-900 border-b border-slate-800 flex justify-between items-center shrink-0">
        <div class="flex items-center gap-2">
          <app-store-icon class="text-blue-500"></app-store-icon>
          <span class="text-[10px] font-black uppercase text-slate-200">{{ adminSettings()?.shopName }}</span>
        </div>
        <div class="flex gap-4">
          @if (isAdmin()) {
            <button (click)="toggleTab()" class="text-blue-500">
              @if (activeTab() === 'calc') {
                <app-users-icon></app-users-icon>
              } @else {
                <app-calculator-icon></app-calculator-icon>
              }
            </button>
          }
          <button (click)="handleLogout()" class="text-rose-600">
            <app-logout-icon></app-logout-icon>
          </button>
        </div>
      </header>
      <main class="flex-1 overflow-hidden">
        @if (activeTab() === 'admin' && isAdmin()) {
          <app-admin-panel></app-admin-panel>
        } @else {
          <app-calculator [defaultShopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'"></app-calculator>
        }
      </main>
    </div>
  }
}

import { Component, ChangeDetectionStrategy, inject, signal, OnInit } from '@angular/core';
import { DataService } from '../../services/data.service';
import { CommonModule } from '@angular/common';
import { Trash2IconComponent } from '../icons/trash2-icon.component';

@Component({
  selector: 'app-admin-panel',
  templateUrl: './admin-panel.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, Trash2IconComponent]
})
export class AdminPanelComponent implements OnInit {
  private dataService = inject(DataService);

  allUsers = this.dataService.allUsers;
  name = signal('');
  expiryDate = signal('');
  noExpiry = signal(false);

  ngOnInit() {
    this.setDefaultExpiryDate();
  }

  private setDefaultExpiryDate() {
    const today = new Date();
    today.setDate(today.getDate() + 30);
    this.expiryDate.set(today.toISOString().split('T')[0]);
  }

  createKey() {
    if (!this.name().trim()) return;
    const expiryValue = this.noExpiry() ? null : this.expiryDate();
    if (!expiryValue && !this.noExpiry()) {
      alert('Please set an expiry date or check "No Expiry".');
      return;
    }
    this.dataService.createNewUser(this.name().trim(), expiryValue);
    this.name.set('');
  }

  deleteUser(userId: string) {
    this.dataService.deleteUser(userId);
  }
}

import { Injectable, signal, OnDestroy } from '@angular/core';

const SETTINGS_KEY = 'fw_admin_settings';
const USERS_KEY = 'fw_users_data';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name: string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

@Injectable({
  providedIn: 'root',
})
export class DataService implements OnDestroy {
  adminSettings = signal<AdminSettings | null>(null);
  allUsers = signal<UserData[]>([]);
  isInitialized = signal(false);

  constructor() {
    this.loadDataFromLocalStorage();
  }

  ngOnDestroy() {
    // No-op, as there are no active subscriptions to clean up.
  }

  private loadDataFromLocalStorage(): void {
    try {
      // Load Admin Settings
      const settingsStr = localStorage.getItem(SETTINGS_KEY);
      if (settingsStr) {
        this.adminSettings.set(JSON.parse(settingsStr));
      } else {
        const defaultSettings: AdminSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
        this.adminSettings.set(defaultSettings);
        localStorage.setItem(SETTINGS_KEY, JSON.stringify(defaultSettings));
      }

      // Load Users
      const usersStr = localStorage.getItem(USERS_KEY);
      this.allUsers.set(usersStr ? JSON.parse(usersStr) : []);

    } catch (e) {
      console.error("Failed to load data from localStorage", e);
      // Fallback to default if storage is corrupt or inaccessible
      const defaultSettings: AdminSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
      this.adminSettings.set(defaultSettings);
      this.allUsers.set([]);
    }

    this.isInitialized.set(true);
  }

  private saveUsersToLocalStorage(): void {
    try {
      localStorage.setItem(USERS_KEY, JSON.stringify(this.allUsers()));
    } catch (e) {
      console.error("Failed to save users to localStorage", e);
    }
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }

  updateUserDevice(userId: string, deviceId: string): void {
    this.allUsers.update(users => 
      users.map(user => 
        user.id === userId ? { ...user, deviceId: deviceId } : user
      )
    );
    this.saveUsersToLocalStorage();
  }

  createNewUser(name: string, expiresAt: string | null): void {
    if (!name) return;

    let key: string;
    let isUnique = false;
    const existingKeys = new Set(this.allUsers().map(u => u.key));

    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!existingKeys.has(key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const userDocId = crypto.randomUUID();
    const newUser: UserData = {
      id: userDocId,
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString(),
      expiresAt,
    };

    this.allUsers.update(users => [...users, newUser]);
    this.saveUsersToLocalStorage();
  }

  deleteUser(userId: string): void {
    this.allUsers.update(users => users.filter(user => user.id !== userId));
    this.saveUsersToLocalStorage();
  }
}

