import { Injectable, signal } from '@angular/core';
import { initializeApp, FirebaseApp } from 'firebase/app';
import { getFirestore, Firestore, doc, getDoc, collection, getDocs, setDoc, updateDoc, deleteDoc, where, query, limit } from 'firebase/firestore';
import { getAuth, Auth, signInAnonymously, onAuthStateChanged, User } from 'firebase/auth';

// These are expected to be provided globally in the execution environment.
declare const __firebase_config: string;
declare const __app_id: string;

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name: string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private app!: FirebaseApp;
  private db!: Firestore;
  private auth!: Auth;
  private appId: string;

  firebaseStatus = signal<'initializing' | 'ready' | 'error'>('initializing');

  adminSettings = signal<AdminSettings | null>(null);
  allUsers = signal<UserData[]>([]);

  constructor() {
    this.appId = typeof __app_id !== 'undefined' ? __app_id : 'future-world-v38';
    this.initializeFirebase();
  }

  private async initializeFirebase(): Promise<void> {
    try {
      const configStr = typeof __firebase_config !== 'undefined' ? __firebase_config : null;
      if (!configStr) {
        throw new Error('Firebase configuration (__firebase_config) is missing.');
      }

      const firebaseConfig = JSON.parse(configStr);
      if (!firebaseConfig || !firebaseConfig.apiKey) {
        throw new Error('Firebase configuration is invalid or missing apiKey.');
      }

      this.app = initializeApp(firebaseConfig);
      this.db = getFirestore(this.app);
      this.auth = getAuth(this.app);

      await signInAnonymously(this.auth);

      onAuthStateChanged(this.auth, async (user) => {
        if (user) {
          await this.fetchAdminSettings();
          this.firebaseStatus.set('ready');
        }
      });

    } catch (error) {
      console.error('Firebase initialization failed:', error);
      this.firebaseStatus.set('error');
    }
  }

  private async fetchAdminSettings(): Promise<void> {
    try {
      const settingsRef = doc(this.db, 'artifacts', this.appId, 'public', 'settings');
      const docSnap = await getDoc(settingsRef);
      if (docSnap.exists()) {
        this.adminSettings.set(docSnap.data() as AdminSettings);
      } else {
        const defaultSettings: AdminSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
        await setDoc(settingsRef, defaultSettings);
        this.adminSettings.set(defaultSettings);
      }
    } catch (error) {
        console.error("Error fetching admin settings:", error);
        this.firebaseStatus.set('error');
    }
  }

  async fetchAllUsers(): Promise<void> {
    try {
        const usersRef = collection(this.db, 'artifacts', this.appId, 'public', 'data', 'users');
        const q = query(usersRef);
        const querySnapshot = await getDocs(q);
        const users = querySnapshot.docs.map(d => d.data() as UserData);
        this.allUsers.set(users);
    } catch(e) {
        console.error("Error fetching all users", e);
    }
  }

  async getUserByKey(key: string): Promise<UserData | null> {
    const usersRef = collection(this.db, 'artifacts', this.appId, 'public', 'data', 'users');
    const q = query(usersRef, where("key", "==", key), limit(1));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) {
        return null;
    }
    return querySnapshot.docs[0].data() as UserData;
  }

  async updateUserDevice(userId: string, deviceId: string): Promise<void> {
    const userDocRef = doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId);
    await updateDoc(userDocRef, { deviceId });
  }

  async createNewUser(name: string, expiresAt: string | null): Promise<void> {
    let key: string;
    let isUnique = false;

    // Ensure uniqueness server-side
    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      const existingUser = await this.getUserByKey(key);
      if (!existingUser) {
        isUnique = true;
      }
    } while (!isUnique);

    const userDocId = crypto.randomUUID();
    const newUser: UserData = {
      id: userDocId, name, key, deviceId: null, createdAt: new Date().toISOString(), expiresAt
    };

    await setDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userDocId), newUser);
    await this.fetchAllUsers();
  }

  async deleteUser(userId: string): Promise<void> {
    await deleteDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId));
    await this.fetchAllUsers();
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }
}

const CACHE_NAME = 'future-world-cache-v1';
const URLS_TO_CACHE = [
  '/',
  '/index.html',
  'https://cdn.tailwindcss.com',
  'https://esm.sh/rxjs@^7.8.2?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/operators?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/ajax?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/webSocket?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/testing?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/fetch?conditions=es2015',
  'https://esm.sh/@angular/common@^21.1.2?external=rxjs',
  'https://esm.sh/@angular/platform-browser@^21.1.2?external=rxjs',
  'https://esm.sh/@angular/core@^21.1.2?external=rxjs',
  'https://esm.sh/@angular/compiler@^21.1.2?external=rxjs',
  'https://esm.sh/firebase@^12.8.0/app?external=rxjs',
  'https://esm.sh/firebase@^12.8.0/firestore?external=rxjs',
  'https://esm.sh/firebase@^12.8.0/auth?external=rxjs'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => {
        console.log('Opened cache');
        return cache.addAll(URLS_TO_CACHE).catch(error => {
          console.error('Failed to cache all resources:', error);
        });
      })
  );
});

self.addEventListener('fetch', event => {
  event.respondWith(
    caches.match(event.request)
      .then(response => {
        // Cache hit - return response
        if (response) {
          return response;
        }

        return fetch(event.request).then(
          response => {
            // Check if we received a valid response
            if (!response || response.status !== 200) {
              return response;
            }

            // We don't cache non-GET requests
            if(event.request.method !== 'GET') {
                return response;
            }

            // IMPORTANT: Clone the response. A response is a stream
            // and because we want the browser to consume the response
            // as well as the cache consuming the response, we need
            // to clone it so we have two streams.
            const responseToCache = response.clone();

            caches.open(CACHE_NAME)
              .then(cache => {
                cache.put(event.request, responseToCache);
              });

            return response;
          }
        ).catch(err => {
            console.log('Fetch failed; returning offline page instead.', err);
            // Optional: return an offline fallback page if a specific resource fails to fetch.
            // For this app, failing to fetch a JS module will break it anyway, so we just let it fail.
        });
      })
  );
});

self.addEventListener('activate', event => {
  const cacheWhitelist = [CACHE_NAME];
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
});

import { Component, ChangeDetectionStrategy, signal, inject, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService } from './services/data.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { SetupComponent, SetupPayload } from './components/setup/setup.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { XCircleIconComponent } from './components/icons/x-circle-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'loading' | 'setup' | 'login' | 'app' | 'error';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    SetupComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
    XCircleIconComponent,
  ],
})
export class AppComponent {
  private dataService = inject(DataService);
  private titleService = inject(Title);

  appState = signal<AppState>('loading');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  myDeviceId = this.dataService.getLocalDeviceId();
  firebaseStatus = this.dataService.firebaseStatus;

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });

    effect(() => {
      const status = this.firebaseStatus();
      if (status === 'ready') {
        this.appState.set('login');
      } else if (status === 'error') {
        this.appState.set('error');
      } else if (status === 'config_missing') {
        this.appState.set('setup');
      }
    });
  }

  async handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const settings = this.adminSettings();
    if (!settings) {
        this.loginError.set('Application settings not found.');
        this.isLoggingIn.set(false);
        return;
    }

    const input = loginInput.trim().toUpperCase();

    // Admin Login
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      await this.dataService.fetchAllUsers();
      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    // User Login
    const userEntry = await this.dataService.getUserByKey(input);

    if (!userEntry) {
      this.loginError.set('ကုဒ်မှားနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check for expiration
    if (userEntry.expiresAt && new Date(userEntry.expiresAt) < new Date()) {
      this.loginError.set('Key သက်တမ်းကုန်နေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check device lock
    if (userEntry.deviceId && userEntry.deviceId !== this.myDeviceId) {
      this.loginError.set('Key ကိုအခြားဖုန်းတွင်အသုံးပြုနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Lock device if not already locked
    if (!userEntry.deviceId) {
      await this.dataService.updateUserDevice(userEntry.id, this.myDeviceId);
    }

    // Success
    this.isAdmin.set(false);
    this.appState.set('app');
    this.activeTab.set('calc');
    this.isLoggingIn.set(false);
  }

  handleConfigSave(payload: SetupPayload) {
    this.dataService.saveConfigAndReload(payload.config, payload.appId);
  }

  handleResetConfig() {
    this.dataService.clearConfigAndReload();
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(null);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  clearLoginError() {
      this.loginError.set(null);
  }
}

@switch (appState()) {
  @case ('loading') {
    <div class="h-screen bg-black flex items-center justify-center text-blue-500 font-bold">Loading...</div>
  }
  @case ('setup') {
    <app-setup (saveConfig)="handleConfigSave($event)"></app-setup>
  }
  @case ('login') {
    <app-login 
      [shopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'" 
      [loginError]="loginError()"
      [isLoggingIn]="isLoggingIn()"
      (loginAttempt)="handleLogin($event)"
      (inputChange)="clearLoginError()">
    </app-login>
  }
  @case ('app') {
    <div class="h-screen bg-black text-white flex flex-col overflow-hidden select-none">
      <header class="px-3 py-2 bg-slate-900 border-b border-slate-800 flex justify-between items-center shrink-0">
        <div class="flex items-center gap-2">
          <app-store-icon class="text-blue-500"></app-store-icon>
          <span class="text-[10px] font-black uppercase text-slate-200">{{ adminSettings()?.shopName }}</span>
        </div>
        <div class="flex gap-4">
          @if (isAdmin()) {
            <button (click)="toggleTab()" class="text-blue-500">
              @if (activeTab() === 'calc') {
                <app-users-icon></app-users-icon>
              } @else {
                <app-calculator-icon></app-calculator-icon>
              }
            </button>
          }
          <button (click)="handleLogout()" class="text-rose-600">
            <app-logout-icon></app-logout-icon>
          </button>
        </div>
      </header>
      <main class="flex-1 overflow-hidden">
        @if (activeTab() === 'admin' && isAdmin()) {
          <app-admin-panel></app-admin-panel>
        } @else {
          <app-calculator [defaultShopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'"></app-calculator>
        }
      </main>
    </div>
  }
  @case('error') {
     <div class="h-screen bg-black flex flex-col items-center justify-center p-6 text-white text-center">
        <app-x-circle-icon class="text-rose-500 mb-4"></app-x-circle-icon>
        <h1 class="text-lg font-bold">Connection Failed</h1>
        <p class="text-slate-400 text-sm mb-6">Please check your internet connection or Firebase configuration.</p>
        <button (click)="handleResetConfig()" class="bg-blue-600 px-4 py-2 rounded-lg font-bold text-xs">Reset Configuration</button>
     </div>
  }
}

import { Injectable, signal } from '@angular/core';
import { initializeApp, FirebaseApp } from 'firebase/app';
import { getFirestore, Firestore, doc, getDoc, collection, getDocs, setDoc, updateDoc, deleteDoc, where, query, limit } from 'firebase/firestore';
import { getAuth, Auth, signInAnonymously, onAuthStateChanged, User } from 'firebase/auth';

const FIREBASE_CONFIG_KEY = 'fw_firebase_config';
const APP_ID_KEY = 'fw_app_id';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name: string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private app!: FirebaseApp;
  private db!: Firestore;
  private auth!: Auth;
  private appId: string | null;

  firebaseStatus = signal<'initializing' | 'config_missing' | 'ready' | 'error'>('initializing');

  adminSettings = signal<AdminSettings | null>(null);
  allUsers = signal<UserData[]>([]);

  constructor() {
    this.appId = localStorage.getItem(APP_ID_KEY);
    const configStr = localStorage.getItem(FIREBASE_CONFIG_KEY);

    if (!configStr || !this.appId) {
      this.firebaseStatus.set('config_missing');
      return;
    }

    this.initializeFirebase(configStr);
  }

  private async initializeFirebase(configStr: string): Promise<void> {
    try {
      const firebaseConfig = JSON.parse(configStr);
      if (!firebaseConfig || !firebaseConfig.apiKey) {
        throw new Error('Firebase configuration is invalid or missing apiKey.');
      }

      this.app = initializeApp(firebaseConfig);
      this.db = getFirestore(this.app);
      this.auth = getAuth(this.app);

      await signInAnonymously(this.auth);

      onAuthStateChanged(this.auth, async (user) => {
        if (user) {
          await this.fetchAdminSettings();
          this.firebaseStatus.set('ready');
        } else {
          // This might happen if auth state is lost, handle appropriately
        }
      });

    } catch (error) {
      console.error('Firebase initialization failed:', error);
      this.firebaseStatus.set('error');
    }
  }

  saveConfigAndReload(configStr: string, appId: string): void {
    try {
      // Validate JSON before saving
      JSON.parse(configStr);
      localStorage.setItem(FIREBASE_CONFIG_KEY, configStr);
      localStorage.setItem(APP_ID_KEY, appId);
      window.location.reload();
    } catch(e) {
      alert("Invalid Firebase Configuration JSON.");
    }
  }

  clearConfigAndReload(): void {
    localStorage.removeItem(FIREBASE_CONFIG_KEY);
    localStorage.removeItem(APP_ID_KEY);
    window.location.reload();
  }

  private async fetchAdminSettings(): Promise<void> {
    if (!this.appId) return;
    try {
      const settingsRef = doc(this.db, 'artifacts', this.appId, 'public', 'settings');
      const docSnap = await getDoc(settingsRef);
      if (docSnap.exists()) {
        this.adminSettings.set(docSnap.data() as AdminSettings);
      } else {
        const defaultSettings: AdminSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
        await setDoc(settingsRef, defaultSettings);
        this.adminSettings.set(defaultSettings);
      }
    } catch (error) {
        console.error("Error fetching admin settings:", error);
        this.firebaseStatus.set('error');
    }
  }

  async fetchAllUsers(): Promise<void> {
    if (!this.appId) return;
    try {
        const usersRef = collection(this.db, 'artifacts', this.appId, 'public', 'data', 'users');
        const q = query(usersRef);
        const querySnapshot = await getDocs(q);
        const users = querySnapshot.docs.map(d => d.data() as UserData);
        this.allUsers.set(users);
    } catch(e) {
        console.error("Error fetching all users", e);
    }
  }

  async getUserByKey(key: string): Promise<UserData | null> {
    if (!this.appId) return null;
    const usersRef = collection(this.db, 'artifacts', this.appId, 'public', 'data', 'users');
    const q = query(usersRef, where("key", "==", key), limit(1));
    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) {
        return null;
    }
    return querySnapshot.docs[0].data() as UserData;
  }

  async updateUserDevice(userId: string, deviceId: string): Promise<void> {
    if (!this.appId) return;
    const userDocRef = doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId);
    await updateDoc(userDocRef, { deviceId });
  }

  async createNewUser(name: string, expiresAt: string | null): Promise<void> {
    if (!this.appId) return;
    let key: string;
    let isUnique = false;

    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      const existingUser = await this.getUserByKey(key);
      if (!existingUser) {
        isUnique = true;
      }
    } while (!isUnique);

    const userDocId = crypto.randomUUID();
    const newUser: UserData = {
      id: userDocId, name, key, deviceId: null, createdAt: new Date().toISOString(), expiresAt
    };

    await setDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userDocId), newUser);
    await this.fetchAllUsers();
  }

  async deleteUser(userId: string): Promise<void> {
    if (!this.appId) return;
    await deleteDoc(doc(this.db, 'artifacts', this.appId, 'public', 'data', 'users', userId));
    await this.fetchAllUsers();
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }
}

import { Component, ChangeDetectionStrategy, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ShieldCheckIconComponent } from '../icons/shield-check-icon.component';

export interface SetupPayload {
  config: string;
  appId: string;
}

@Component({
  selector: 'app-setup',
  templateUrl: './setup.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, ShieldCheckIconComponent]
})
export class SetupComponent {
  saveConfig = output<SetupPayload>();

  masterPassword = signal('');
  firebaseConfig = signal('');
  appId = signal('');
  error = signal<string | null>(null);

  // Use a hardcoded default master password for the initial setup.
  // This can be changed in Firebase by the admin later.
  private readonly SETUP_MASTER_PASS = 'MasterSaiYan';

  onSave() {
    this.error.set(null);
    const pass = this.masterPassword().trim();
    const config = this.firebaseConfig().trim();
    const id = this.appId().trim();

    if (pass.toUpperCase() !== this.SETUP_MASTER_PASS.toUpperCase()) {
      this.error.set('Master Password is required.');
      return;
    }

    if (!config || !id) {
      this.error.set('Firebase Config and App ID are required.');
      return;
    }

    try {
      JSON.parse(config);
    } catch (e) {
      this.error.set('Firebase Config must be a valid JSON object.');
      return;
    }

    this.saveConfig.emit({ config, appId: id });
  }
}

import { Component, ChangeDetectionStrategy, inject, signal, OnInit, computed } from '@angular/core';
import { DataService, UserData } from '../../services/data.service';
import { CommonModule } from '@angular/common';
import { Trash2IconComponent } from '../icons/trash2-icon.component';

@Component({
  selector: 'app-admin-panel',
  templateUrl: './admin-panel.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, Trash2IconComponent]
})
export class AdminPanelComponent implements OnInit {
  private dataService = inject(DataService);

  allUsers = this.dataService.allUsers;
  sortedUsers = computed(() => {
    return this.allUsers().slice().sort((a: UserData, b: UserData) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  });

  name = signal('');
  expiryDate = signal('');
  noExpiry = signal(false);

  ngOnInit() {
    this.setDefaultExpiryDate();
  }

  private setDefaultExpiryDate() {
    const today = new Date();
    today.setDate(today.getDate() + 30);
    this.expiryDate.set(today.toISOString().split('T')[0]);
  }

  async createKey() {
    if (!this.name().trim()) return;
    const expiryValue = this.noExpiry() ? null : this.expiryDate();
    if (!expiryValue && !this.noExpiry()) {
      alert('Please set an expiry date or check "No Expiry".');
      return;
    }
    await this.dataService.createNewUser(this.name().trim(), expiryValue);
    this.name.set('');
  }

  async deleteUser(userId: string) {
    if (confirm('Are you sure you want to delete this user?')) {
        await this.dataService.deleteUser(userId);
    }
  }
}

import { Component, ChangeDetectionStrategy, signal, inject, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService } from './services/data.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'login' | 'app';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
  ],
})
export class AppComponent {
  private dataService = inject(DataService);
  private titleService = inject(Title);

  appState = signal<AppState>('login');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  myDeviceId = this.dataService.getLocalDeviceId();

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });
  }

  handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const settings = this.adminSettings();
    if (!settings) {
        this.loginError.set('Application settings not found.');
        this.isLoggingIn.set(false);
        return;
    }

    const input = loginInput.trim().toUpperCase();

    // Admin Login
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      this.dataService.fetchAllUsers();
      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    // User Login
    const userEntry = this.dataService.getUserByKey(input);

    if (!userEntry) {
      this.loginError.set('ကုဒ်မှားနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check for expiration
    if (userEntry.expiresAt && new Date(userEntry.expiresAt) < new Date()) {
      this.loginError.set('Key သက်တမ်းကုန်နေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check device lock
    if (userEntry.deviceId && userEntry.deviceId !== this.myDeviceId) {
      this.loginError.set('Key ကိုအခြားဖုန်းတွင်အသုံးပြုနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Lock device if not already locked
    if (!userEntry.deviceId) {
      this.dataService.updateUserDevice(userEntry.id, this.myDeviceId);
    }

    // Success
    this.isAdmin.set(false);
    this.appState.set('app');
    this.activeTab.set('calc');
    this.isLoggingIn.set(false);
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(null);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  clearLoginError() {
      this.loginError.set(null);
  }
}

@switch (appState()) {
  @case ('login') {
    <app-login 
      [shopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'" 
      [loginError]="loginError()"
      [isLoggingIn]="isLoggingIn()"
      (loginAttempt)="handleLogin($event)"
      (inputChange)="clearLoginError()">
    </app-login>
  }
  @case ('app') {
    <div class="h-screen bg-black text-white flex flex-col overflow-hidden select-none">
      <header class="px-3 py-2 bg-slate-900 border-b border-slate-800 flex justify-between items-center shrink-0">
        <div class="flex items-center gap-2">
          <app-store-icon class="text-blue-500"></app-store-icon>
          <span class="text-[10px] font-black uppercase text-slate-200">{{ adminSettings()?.shopName }}</span>
        </div>
        <div class="flex gap-4">
          @if (isAdmin()) {
            <button (click)="toggleTab()" class="text-blue-500">
              @if (activeTab() === 'calc') {
                <app-users-icon></app-users-icon>
              } @else {
                <app-calculator-icon></app-calculator-icon>
              }
            </button>
          }
          <button (click)="handleLogout()" class="text-rose-600">
            <app-logout-icon></app-logout-icon>
          </button>
        </div>
      </header>
      <main class="flex-1 overflow-hidden">
        @if (activeTab() === 'admin' && isAdmin()) {
          <app-admin-panel></app-admin-panel>
        } @else {
          <app-calculator [defaultShopName]="adminSettings()?.shopName || 'အနာဂတ်ကမ္ဘာ'"></app-calculator>
        }
      </main>
    </div>
  }
}

