import { Component, ChangeDetectionStrategy, input, output, signal } from '@angular/core';
import { ShieldCheckIconComponent } from '../icons/shield-check-icon.component';
import { CopyIconComponent } from '../icons/copy-icon.component';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [ShieldCheckIconComponent, CopyIconComponent]
})
export class LoginComponent {
  shopName = input.required<string>();
  loginError = input<string | null>(null);
  isLoggingIn = input(false);
  deviceId = input.required<string>();
  loginAttempt = output<string>();
  inputChange = output<void>();

  loginInput = signal('');
  copied = signal(false);

  onLogin() {
    this.loginAttempt.emit(this.loginInput());
  }

  onInputChange(event: Event) {
    const value = (event.target as HTMLInputElement).value;
    this.loginInput.set(value);
    this.inputChange.emit();
  }

  async copyDeviceId(id: string) {
    try {
      await navigator.clipboard.writeText(id);
      this.copied.set(true);
      setTimeout(() => this.copied.set(false), 2000);
    } catch (err) {
      console.error('Failed to copy device ID: ', err);
    }
  }
}

