import { Injectable, signal } from '@angular/core';
import { initializeApp, FirebaseApp } from 'firebase/app';
import { 
  getFirestore, 
  Firestore, 
  collection, 
  doc, 
  getDoc, 
  setDoc, 
  getDocs, 
  deleteDoc,
  updateDoc,
  query,
  where,
  writeBatch
} from 'firebase/firestore';
import { AdminSettings, UserData } from './data.service';

@Injectable({
  providedIn: 'root'
})
export class FirebaseService {
  private app: FirebaseApp | null = null;
  private db: Firestore | null = null;
  private appId = signal<string | null>(null);

  isInitialized = signal(false);

  constructor() {}

  async initialize(config: any, appId: string): Promise<boolean> {
    try {
      if (this.app) return true; // Already initialized
      this.app = initializeApp(config);
      this.db = getFirestore(this.app);
      this.appId.set(appId);
      this.isInitialized.set(true);
      return true;
    } catch (error) {
      console.error("Firebase initialization failed:", error);
      this.isInitialized.set(false);
      return false;
    }
  }

  private getCollectionPath(collectionName: string): string {
    return `apps/${this.appId()}/${collectionName}`;
  }

  async getAdminSettings(): Promise<AdminSettings | null> {
    if (!this.db) return null;
    const docRef = doc(this.db, this.getCollectionPath('settings'), 'admin');
    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? docSnap.data() as AdminSettings : null;
  }

  async updateAdminSettings(settings: Partial<AdminSettings>): Promise<void> {
    if (!this.db) return;
    const docRef = doc(this.db, this.getCollectionPath('settings'), 'admin');
    await setDoc(docRef, settings, { merge: true });
  }

  async getAllUsers(): Promise<UserData[]> {
    if (!this.db) return [];
    const q = collection(this.db, this.getCollectionPath('users'));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as UserData);
  }

  async getUserByKey(key: string): Promise<UserData | null> {
    if (!this.db) return null;
    const usersRef = collection(this.db, this.getCollectionPath('users'));
    const q = query(usersRef, where("key", "==", key.toUpperCase()));
    const querySnapshot = await getDocs(q);
    if (!querySnapshot.empty) {
      return querySnapshot.docs[0].data() as UserData;
    }
    return null;
  }

  async createNewUser(user: UserData): Promise<void> {
    if (!this.db) return;
    const docRef = doc(this.db, this.getCollectionPath('users'), user.id);
    await setDoc(docRef, user);
  }

  async updateUserDevice(userId: string, deviceId: string | null): Promise<void> {
    if (!this.db) return;
    const docRef = doc(this.db, this.getCollectionPath('users'), userId);
    await updateDoc(docRef, { deviceId });
  }

  async deleteUser(userId: string): Promise<void> {
    if (!this.db) return;
    const docRef = doc(this.db, this.getCollectionPath('users'), userId);
    await deleteDoc(docRef);
  }

  async factoryReset(): Promise<void> {
    if (!this.db) return;

    // Delete all users
    const usersRef = collection(this.db, this.getCollectionPath('users'));
    const usersSnapshot = await getDocs(usersRef);
    const batch = writeBatch(this.db);
    usersSnapshot.forEach(doc => {
      batch.delete(doc.ref);
    });

    // Delete settings
    const settingsRef = doc(this.db, this.getCollectionPath('settings'), 'admin');
    batch.delete(settingsRef);

    await batch.commit();
  }
}

import { Injectable, signal, computed, inject } from '@angular/core';
import { FirebaseService } from './firebase.service';

const CONFIG_KEY = 'fw_firebase_config_v2';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name:string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

interface StoredConfig {
    config: any;
    appId: string;
}

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private firebaseService = inject(FirebaseService);

  private adminSettingsState = signal<AdminSettings | null>(null);
  private usersState = signal<UserData[]>([]);

  isInitialized = this.firebaseService.isInitialized;
  adminSettings = computed(() => this.adminSettingsState());
  allUsers = computed(() => this.usersState());

  async initialize(): Promise<'success' | 'setup_required'> {
    const stored = localStorage.getItem(CONFIG_KEY);
    if (!stored) {
      return 'setup_required';
    }
    try {
      const { config, appId } = JSON.parse(stored);
      const success = await this.firebaseService.initialize(config, appId);
      if (success) {
        await this.loadInitialData();
        return 'success';
      } else {
        localStorage.removeItem(CONFIG_KEY);
        return 'setup_required';
      }
    } catch(e) {
      console.error("Failed to parse stored config", e);
      localStorage.removeItem(CONFIG_KEY);
      return 'setup_required';
    }
  }

  async saveConfiguration(config: any, appId: string): Promise<boolean> {
      const success = await this.firebaseService.initialize(config, appId);
      if (success) {
          localStorage.setItem(CONFIG_KEY, JSON.stringify({ config, appId }));
          await this.loadInitialData();
          // If no admin settings exist on remote, create default ones.
          if (!this.adminSettingsState()) {
              const defaultSettings = { masterPass: 'MasterSaiYan', shopName: 'အနာဂတ်ကမ္ဘာ' };
              await this.firebaseService.updateAdminSettings(defaultSettings);
              this.adminSettingsState.set(defaultSettings);
          }
      }
      return success;
  }

  async loadInitialData(): Promise<void> {
    await this.loadAdminSettings();
    await this.fetchAllUsers();
  }

  async loadAdminSettings(): Promise<void> {
      const settings = await this.firebaseService.getAdminSettings();
      this.adminSettingsState.set(settings);
  }

  async fetchAllUsers(): Promise<void> {
    const users = await this.firebaseService.getAllUsers();
    this.usersState.set(users);
  }

  async getUserByKey(key: string): Promise<UserData | null> {
    // Check local cache first for performance
    const localUser = this.allUsers().find(u => u.key.toUpperCase() === key.toUpperCase());
    if (localUser) return localUser;

    // If not found, query from Firebase directly
    return await this.firebaseService.getUserByKey(key);
  }

  async updateUserDevice(userId: string, deviceId: string | null): Promise<void> {
    await this.firebaseService.updateUserDevice(userId, deviceId);
    this.usersState.update(users => 
      users.map(u => u.id === userId ? { ...u, deviceId } : u)
    );
  }

  async updateAdminSettings(settings: Partial<AdminSettings>): Promise<void> {
    await this.firebaseService.updateAdminSettings(settings);
    this.adminSettingsState.update(current => ({ ...current!, ...settings }));
  }

  async createNewUser(name: string, expiresAt: string | null, deviceId: string | null = null): Promise<void> {
    let key: string;
    let isUnique = false;
    const existingKeys = new Set(this.allUsers().map(u => u.key));

    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!existingKeys.has(key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const userDocId = crypto.randomUUID();
    const newUser: UserData = {
      id: userDocId, name, key, deviceId, createdAt: new Date().toISOString(), expiresAt
    };

    await this.firebaseService.createNewUser(newUser);
    this.usersState.update(users => [...users, newUser]);
  }

  async deleteUser(userId: string): Promise<void> {
     await this.firebaseService.deleteUser(userId);
     this.usersState.update(users => users.filter(u => u.id !== userId));
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }

  async factoryReset(): Promise<void> {
    await this.firebaseService.factoryReset();
    localStorage.removeItem(CONFIG_KEY);
    localStorage.removeItem('fw_device_id');
    localStorage.removeItem('fw_my_shop_name');
    location.reload();
  }
}

