    } catch (error) {
      console.error("Failed to create user:", error);
      alert('Failed to create user. Please check the server.');
    }
  }

  async deleteUser(userId: string): Promise<void> {
    try {
      await firstValueFrom(this.http.delete(`/api/users/${userId}`));
      this.usersState.update(users => users.filter(u => u.id !== userId));
    } catch (error) {
      console.error(`Failed to delete user ${userId}:`, error);
      alert('Failed to delete user. Please check the server.');
    }
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
