const CACHE_NAME = 'future-world-cache-v1';
const URLS_TO_CACHE = [
  '/',
  '/index.html',
  'https://cdn.tailwindcss.com',
  'https://esm.sh/rxjs@^7.8.2?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/operators?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/ajax?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/webSocket?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/testing?conditions=es2015',
  'https://esm.sh/rxjs@^7.8.2/fetch?conditions=es2015',
  'https://esm.sh/@angular/common@^21.1.2?external=rxjs',
  'https://esm.sh/@angular/common@^21.1.2/http?external=rxjs',
  'https://esm.sh/@angular/platform-browser@^21.1.2?external=rxjs',
  'https://esm.sh/@angular/core@^21.1.2?external=rxjs',
  'https://esm.sh/@angular/compiler@^21.1.2?external=rxjs'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => {
        console.log('Opened cache');
        return cache.addAll(URLS_TO_CACHE).catch(error => {
          console.error('Failed to cache all resources:', error);
        });
      })
  );
});

self.addEventListener('fetch', event => {
  event.respondWith(
    caches.match(event.request)
      .then(response => {
        // Cache hit - return response
        if (response) {
          return response;
        }

        return fetch(event.request).then(
          response => {
            // Check if we received a valid response
            if (!response || response.status !== 200) {
              return response;
            }

            // We don't cache non-GET requests
            if(event.request.method !== 'GET') {
                return response;
            }

            // IMPORTANT: Clone the response. A response is a stream
            // and because we want the browser to consume the response
            // as well as the cache consuming the response, we need
            // to clone it so we have two streams.
            const responseToCache = response.clone();

            caches.open(CACHE_NAME)
              .then(cache => {
                cache.put(event.request, responseToCache);
              });

            return response;
          }
        ).catch(err => {
            console.log('Fetch failed; returning offline page instead.', err);
            // Optional: return an offline fallback page if a specific resource fails to fetch.
            // For this app, failing to fetch a JS module will break it anyway, so we just let it fail.
        });
      })
  );
});

self.addEventListener('activate', event => {
  const cacheWhitelist = [CACHE_NAME];
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
});

import { Component, ChangeDetectionStrategy, signal, inject, effect, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService } from './services/data.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'initializing' | 'error' | 'login' | 'app';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
  ],
})
export class AppComponent implements OnInit {
  private dataService = inject(DataService);
  private titleService = inject(Title);

  appState = signal<AppState>('initializing');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  myDeviceId = this.dataService.getLocalDeviceId();

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });
  }

  async ngOnInit() {
    const initState = await this.dataService.initialize();
    if (initState === 'success') {
      this.appState.set('login');
    } else {
      this.appState.set('error');
    }
  }

  retry() {
    location.reload();
  }

  handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const input = loginInput.trim().toUpperCase();
    const settings = this.adminSettings();
    const users = this.dataService.allUsers();

    if (!settings) {
      this.loginError.set('Application data could not be loaded.');
      this.isLoggingIn.set(false);
      return;
    }

    // Admin Login
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    // User Login
    const user = users.find(u => u.key.toUpperCase() === input);

    if (!user) {
      this.loginError.set('ကုဒ်မှားနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check for expiration
    if (user.expiresAt && new Date(user.expiresAt) < new Date()) {
      this.loginError.set('Key သက်တမ်းကုန်နေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Success
    this.isAdmin.set(false);
    this.appState.set('app');
    this.activeTab.set('calc');
    this.isLoggingIn.set(false);
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(null);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  clearLoginError() {
      this.loginError.set(null);
  }
}

import { Injectable, signal, computed, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name:string;
  key: string;
  deviceId: string | null; // Note: No longer used for login validation
  createdAt: string;
  expiresAt: string | null;
}

interface Database {
  settings: AdminSettings;
  users: UserData[];
}

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private http = inject(HttpClient);

  private database = signal<Database | null>(null);

  adminSettings = computed(() => this.database()?.settings ?? null);
  allUsers = computed(() => this.database()?.users ?? []);

  async initialize(): Promise<'success' | 'error'> {
    try {
      // Add cache-busting query param to ensure fresh data on each load
      const data = await firstValueFrom(this.http.get<Database>(`/api/data?t=${new Date().getTime()}`));
      this.database.set(data);
      return 'success';
    } catch (error) {
      console.error("Failed to fetch initial data:", error);
      this.database.set(null);
      return 'error';
    }
  }

  private async _saveDatabase(): Promise<void> {
    const currentData = this.database();
    if (!currentData) return;

    try {
      await firstValueFrom(this.http.post('/api/data', currentData));
    } catch (error) {
      console.error("Failed to save data:", error);
      alert('Failed to save data to the server. Please check the server and try again.');
      // Optional: Could implement a retry mechanism or revert optimistic updates here
    }
  }

  async updateAdminSettings(newSettings: Partial<AdminSettings>): Promise<void> {
    this.database.update(db => {
        if (!db) return null;
        return { ...db, settings: { ...db.settings, ...newSettings } };
    });
    await this._saveDatabase();
  }

  async createNewUser(name: string, expiresAt: string | null): Promise<void> {
    let key: string;
    let isUnique = false;

    // Ensure key is unique
    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!this.allUsers().some(u => u.key === key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const newUser: UserData = {
      id: crypto.randomUUID(),
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString(),
      expiresAt
    };

    this.database.update(db => {
      if (!db) return null;
      return { ...db, users: [...db.users, newUser] };
    });

    await this._saveDatabase();
  }

  async deleteUser(userId: string): Promise<void> {
    this.database.update(db => {
      if (!db) return null;
      return { ...db, users: db.users.filter(u => u.id !== userId) };
    });
    await this._saveDatabase();
  }

  getLocalDeviceId(): string {
    let id = localStorage.getItem('fw_device_id');
    if (!id) {
      id = 'DEV-' + Math.random().toString(36).substring(2, 9).toUpperCase();
      localStorage.setItem('fw_device_id', id);
    }
    return id;
  }

  async factoryReset(): Promise<void> {
    try {
        await firstValueFrom(this.http.post('/api/factory-reset', {}));
        alert('Factory reset command sent to server. The application will now reload.');
        location.reload();
    } catch(error) {
        console.error('Factory reset failed:', error);
        alert('Factory reset failed. Check server logs.');
    }
  }
}

import { Component, ChangeDetectionStrategy, inject, signal, OnInit, computed } from '@angular/core';
import { DataService, UserData, AdminSettings } from '../../services/data.service';
import { CommonModule } from '@angular/common';
import { Trash2IconComponent } from '../icons/trash2-icon.component';
import { SettingsIconComponent } from '../icons/settings-icon.component';
import { UsersIconComponent } from '../icons/users-icon.component';
import { ShareIconComponent } from '../icons/share-icon.component';
import { CheckIconComponent } from '../icons/check-icon.component';
import { XCircleIconComponent } from '../icons/x-circle-icon.component';

@Component({
  selector: 'app-admin-panel',
  templateUrl: './admin-panel.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, Trash2IconComponent, SettingsIconComponent, UsersIconComponent, ShareIconComponent, CheckIconComponent, XCircleIconComponent]
})
export class AdminPanelComponent implements OnInit {
  private dataService = inject(DataService);

  allUsers = this.dataService.allUsers;
  adminSettings = this.dataService.adminSettings;

  sortedUsers = computed(() => {
    return this.allUsers().slice().sort((a: UserData, b: UserData) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  });

  // User creation state
  name = signal('');
  expiryDate = signal('');
  noExpiry = signal(false);

  // New state for tabs and settings
  activeAdminTab = signal<'users' | 'settings'>('users');
  shopNameInput = signal('');
  masterPassInput = signal('');
  settingsSaved = signal(false);
  copiedKeyId = signal<string | null>(null);

  ngOnInit() {
    this.setDefaultExpiryDate();
    const currentSettings = this.adminSettings();
    if (currentSettings) {
      this.shopNameInput.set(currentSettings.shopName);
      this.masterPassInput.set(currentSettings.masterPass);
    }
  }

  private setDefaultExpiryDate() {
    const today = new Date();
    today.setDate(today.getDate() + 30);
    this.expiryDate.set(today.toISOString().split('T')[0]);
  }

  async createKey() {
    if (!this.name().trim()) return;
    const expiryValue = this.noExpiry() ? null : this.expiryDate();
    if (!expiryValue && !this.noExpiry()) {
      alert('Please set an expiry date or check "No Expiry".');
      return;
    }
    await this.dataService.createNewUser(this.name().trim(), expiryValue);
    this.name.set('');
  }

  async deleteUser(userId: string) {
    if (confirm('Are you sure you want to delete this user?')) {
        await this.dataService.deleteUser(userId);
    }
  }

  async saveSettings() {
    const shopName = this.shopNameInput().trim();
    const masterPass = this.masterPassInput().trim();

    if (!shopName || !masterPass) {
      alert('Shop name and master password cannot be empty.');
      return;
    }

    await this.dataService.updateAdminSettings({ shopName, masterPass });
    this.settingsSaved.set(true);
    setTimeout(() => this.settingsSaved.set(false), 2000);
  }

  async shareKey(user: UserData) {
    const expiryText = user.expiresAt ? new Date(user.expiresAt).toLocaleDateString('en-GB') : 'Never';
    const textToCopy = `အမည်: ${user.name}\nကုဒ် (Key): ${user.key}\nသက်တမ်းကုန်ဆုံးရက်: ${expiryText}`;
    try {
        await navigator.clipboard.writeText(textToCopy);
        this.copiedKeyId.set(user.id);
        setTimeout(() => this.copiedKeyId.set(null), 2000);
    } catch (err) {
        console.error('Failed to copy key: ', err);
        alert('Failed to copy key.');
    }
  }

  async factoryReset() {
    if (confirm('Are you sure you want to delete ALL users and settings? This action cannot be undone.')) {
        await this.dataService.factoryReset();
    }
  }
}

