import { Injectable, signal } from '@angular/core';
import { AdminSettings, UserData } from './data.service';
import { Subject } from 'rxjs';

// Declare firebase to access the global object from index.html
declare const window: any;

export interface Database {
  settings: AdminSettings;
  users: UserData[];
}

@Injectable({
  providedIn: 'root',
})
export class FirebaseService {
  private db: any = null; // Firestore instance
  private app: any = null; // Firebase app instance

  database$ = new Subject<Database>();

  private unsubSettings: any;
  private unsubUsers: any;

  initializeFirebase(config: object): Promise<boolean> {
    return new Promise((resolve) => {
      try {
        if (this.app) {
          // Firebase already initialized
          resolve(true);
          return;
        }

        this.app = window.firebase.initializeApp(config);
        this.db = window.firebase.getFirestore(this.app);
        resolve(true);
      } catch (error) {
        console.error('Firebase initialization failed:', error);
        resolve(false);
      }
    });
  }

  async listenToData() {
    if (!this.db) return;

    // Stop existing listeners
    if (this.unsubSettings) this.unsubSettings();
    if (this.unsubUsers) this.unsubUsers();

    let settings: AdminSettings | null = null;
    let users: UserData[] = [];

    const emitUpdate = () => {
      if (settings !== null) {
        this.database$.next({ settings, users });
      }
    };

    // Listener for Settings
    this.unsubSettings = window.firebase.onSnapshot(
      window.firebase.doc(this.db, 'app/settings'),
      async (docSnap: any) => {
        if (docSnap.exists()) {
          settings = docSnap.data() as AdminSettings;
        } else {
          // First run, create default settings
          const defaultSettings: AdminSettings = {
            shopName: 'My Shop',
            masterPass: '1234',
          };
          await this.updateAdminSettings(defaultSettings);
          settings = defaultSettings;
        }
        emitUpdate();
      },
      (error: any) => console.error("Error listening to settings:", error)
    );

    // Listener for Users
    this.unsubUsers = window.firebase.onSnapshot(
      window.firebase.collection(this.db, 'users'),
      (querySnapshot: any) => {
        users = querySnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() }));
        emitUpdate();
      },
      (error: any) => console.error("Error listening to users:", error)
    );
  }

  async updateAdminSettings(newSettings: AdminSettings): Promise<void> {
    if (!this.db) return;
    const settingsRef = window.firebase.doc(this.db, 'app', 'settings');
    await window.firebase.setDoc(settingsRef, newSettings, { merge: true });
  }

  async createNewUser(user: Omit<UserData, 'id'>): Promise<void> {
    if (!this.db) return;
    await window.firebase.addDoc(window.firebase.collection(this.db, 'users'), user);
  }

  async deleteUser(userId: string): Promise<void> {
    if (!this.db) return;
    await window.firebase.deleteDoc(window.firebase.doc(this.db, 'users', userId));
  }
}

import { Injectable, signal, computed, inject } from '@angular/core';
import { FirebaseService } from './firebase.service';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name: string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

const CONFIG_KEY = 'fw_firebase_config';

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private firebaseService = inject(FirebaseService);
  private database = signal<{settings: AdminSettings, users: UserData[]} | null>(null);

  adminSettings = computed(() => this.database()?.settings ?? null);
  allUsers = computed(() => this.database()?.users ?? []);

  constructor() {
    this.firebaseService.database$.subscribe(db => {
      this.database.set(db);
    });
  }

  async initialize(): Promise<'setup' | 'success' | 'error'> {
    try {
      const configStr = localStorage.getItem(CONFIG_KEY);
      if (!configStr) {
        return 'setup';
      }

      const config = JSON.parse(configStr);
      const initialized = await this.firebaseService.initializeFirebase(config);

      if (initialized) {
        await this.firebaseService.listenToData();
        return 'success';
      } else {
        localStorage.removeItem(CONFIG_KEY); // Remove bad config
        return 'error';
      }
    } catch (error) {
      console.error("Failed to initialize data service:", error);
      return 'error';
    }
  }

  saveFirebaseConfig(config: object): boolean {
    try {
      localStorage.setItem(CONFIG_KEY, JSON.stringify(config));
      return true;
    } catch (e) {
      console.error('Could not save Firebase config', e);
      return false;
    }
  }

  async updateAdminSettings(newSettings: Partial<AdminSettings>): Promise<void> {
    const currentSettings = this.adminSettings();
    if (!currentSettings) return;

    const updated = { ...currentSettings, ...newSettings };
    await this.firebaseService.updateAdminSettings(updated);
  }

  async createNewUser(name: string, expiresAt: string | null): Promise<void> {
    let key: string;
    let isUnique = false;

    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!this.allUsers().some(u => u.key === key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const newUser: Omit<UserData, 'id'> = {
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString(),
      expiresAt
    };

    await this.firebaseService.createNewUser(newUser);
  }

  async deleteUser(userId: string): Promise<void> {
    await this.firebaseService.deleteUser(userId);
  }
}

