import { Component, ChangeDetectionStrategy, output, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { DataService } from '../../services/data.service';
import { FirebaseService } from '../../services/firebase.service';

@Component({
  selector: 'app-setup',
  templateUrl: './setup.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, ReactiveFormsModule],
})
export class SetupComponent {
  private fb = inject(FormBuilder);
  private dataService = inject(DataService);
  private firebaseService = inject(FirebaseService);

  setupComplete = output<void>();

  isSaving = signal(false);
  errorMessage = signal<string | null>(null);

  setupForm = this.fb.group({
    apiKey: ['', Validators.required],
    authDomain: ['', Validators.required],
    projectId: ['', Validators.required],
    storageBucket: ['', Validators.required],
    messagingSenderId: ['', Validators.required],
    appId: ['', Validators.required],
  });

  async saveConfig() {
    if (this.setupForm.invalid) {
      this.errorMessage.set('Please fill in all fields.');
      return;
    }

    this.isSaving.set(true);
    this.errorMessage.set(null);

    const config = this.setupForm.value;

    const initialized = await this.firebaseService.initializeFirebase(config);

    if (initialized) {
      const saved = this.dataService.saveFirebaseConfig(config);
      if (saved) {
        this.setupComplete.emit();
      } else {
        this.errorMessage.set('Could not save configuration locally.');
        this.isSaving.set(false);
      }
    } else {
      this.errorMessage.set('Firebase initialization failed. Please check your configuration values.');
      this.isSaving.set(false);
    }
  }
}

import { Component, ChangeDetectionStrategy, signal, inject, effect, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService } from './services/data.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'initializing' | 'error' | 'login' | 'app';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
  ],
})
export class AppComponent implements OnInit {
  private dataService = inject(DataService);
  private titleService = inject(Title);

  appState = signal<AppState>('initializing');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  users = this.dataService.allUsers;

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });
  }

  async ngOnInit() {
    this.initializeApp();
  }

  async initializeApp() {
    this.appState.set('initializing');
    const initState = await this.dataService.initialize();
    this.appState.set(initState);
  }

  retry() {
    location.reload();
  }

  handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const input = loginInput.trim().toUpperCase();
    const settings = this.adminSettings();
    const users = this.users();

    if (!settings) {
      this.loginError.set('Application data could not be loaded.');
      this.isLoggingIn.set(false);
      return;
    }

    // Admin Login
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    // User Login
    const user = users.find(u => u.key.toUpperCase() === input);

    if (!user) {
      this.loginError.set('ကုဒ်မှားနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check for expiration
    if (user.expiresAt && new Date(user.expiresAt) < new Date()) {
      this.loginError.set('Key သက်တမ်းကုန်နေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Success
    this.isAdmin.set(false);
    this.appState.set('app');
    this.activeTab.set('calc');
    this.isLoggingIn.set(false);
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(null);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  clearLoginError() {
      this.loginError.set(null);
  }
}

@switch (appState()) {
  @case ('initializing') {
    <div class="h-screen bg-black flex items-center justify-center">
      <p class="text-white font-black animate-pulse">Loading data...</p>
    </div>
  }
  @case ('error') {
    <div class="h-screen bg-black flex flex-col items-center justify-center p-6 text-white">
      <div class="w-full max-w-sm bg-slate-900 border border-rose-800 p-8 rounded-3xl text-center">
        <h1 class="text-xl font-black mb-1 text-rose-500">Application Error</h1>
        <p class="text-xs text-slate-400">Could not load data from your browser's storage. Please try again.</p>
        <button (click)="retry()" class="w-full bg-blue-600 p-3 mt-6 rounded-xl font-black text-sm">
          Retry
        </button>
      </div>
    </div>
  }
  @case ('login') {
    <app-login 
      [shopName]="adminSettings()?.shopName || 'Future World'" 
      [loginError]="loginError()"
      [isLoggingIn]="isLoggingIn()"
      (loginAttempt)="handleLogin($event)"
      (inputChange)="clearLoginError()">
    </app-login>
  }
  @case ('app') {
    <div class="h-screen bg-black text-white flex flex-col overflow-hidden select-none">
      <header class="px-3 py-2 bg-slate-900 border-b border-slate-800 flex justify-between items-center shrink-0">
        <div class="flex items-center gap-2">
          <app-store-icon [size]="14" class="text-blue-500"></app-store-icon>
          <span class="text-[10px] font-black uppercase text-slate-200">{{ adminSettings()?.shopName }}</span>
        </div>
        <div class="flex gap-4">
          @if (isAdmin()) {
            <button (click)="toggleTab()" class="text-blue-500">
              @if (activeTab() === 'calc') {
                <app-users-icon [size]="18"></app-users-icon>
              } @else {
                <app-calculator-icon [size]="18"></app-calculator-icon>
              }
            </button>
          }
          <button (click)="handleLogout()" class="text-rose-600">
            <app-logout-icon [size]="18"></app-logout-icon>
          </button>
        </div>
      </header>
      <main class="flex-1 overflow-hidden">
        @if (activeTab() === 'admin' && isAdmin()) {
          <app-admin-panel></app-admin-panel>
        } @else {
          <app-calculator [defaultShopName]="adminSettings()?.shopName || 'Future World'"></app-calculator>
        }
      </main>
    </div>
  }
}

import { Injectable, signal, computed } from '@angular/core';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name:string;
  key: string;
  deviceId: string | null; // Note: No longer used for login validation
  createdAt: string;
  expiresAt: string | null;
}

interface Database {
  settings: AdminSettings;
  users: UserData[];
}

const DB_KEY = 'fw_database';

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private database = signal<Database | null>(null);

  adminSettings = computed(() => this.database()?.settings ?? null);
  allUsers = computed(() => this.database()?.users ?? []);

  async initialize(): Promise<'login' | 'error'> {
    try {
      // Short delay to allow UI to show initializing state
      await new Promise(resolve => setTimeout(resolve, 50)); 

      const storedData = localStorage.getItem(DB_KEY);
      if (storedData) {
        this.database.set(JSON.parse(storedData));
      } else {
        // Create default initial state
        const defaultDb: Database = {
            settings: {
                shopName: 'My Shop',
                masterPass: '1234'
            },
            users: []
        };
        this.database.set(defaultDb);
        this._saveDatabase();
      }
      return 'login';
    } catch (error) {
      console.error("Failed to initialize data from localStorage:", error);
      this.database.set(null);
      return 'error';
    }
  }

  private _saveDatabase(): void {
    const currentData = this.database();
    if (!currentData) return;
    try {
      localStorage.setItem(DB_KEY, JSON.stringify(currentData));
    } catch (error) {
      console.error("Failed to save data to localStorage:", error);
      alert('Failed to save data. Your browser might be in private mode or storage is full.');
    }
  }

  updateAdminSettings(newSettings: Partial<AdminSettings>): void {
    this.database.update(db => {
        if (!db) return null;
        return { ...db, settings: { ...db.settings, ...newSettings } };
    });
    this._saveDatabase();
  }

  createNewUser(name: string, expiresAt: string | null): void {
    let key: string;
    let isUnique = false;

    // Ensure key is unique
    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!this.allUsers().some(u => u.key === key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const newUser: UserData = {
      id: crypto.randomUUID(),
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString(),
      expiresAt
    };

    this.database.update(db => {
      if (!db) return null;
      return { ...db, users: [...db.users, newUser] };
    });

    this._saveDatabase();
  }

  deleteUser(userId: string): void {
    this.database.update(db => {
      if (!db) return null;
      return { ...db, users: db.users.filter(u => u.id !== userId) };
    });
    this._saveDatabase();
  }

  factoryReset(): void {
    if (confirm('Are you sure you want to delete ALL users and settings? This action cannot be undone. It is recommended to backup data first.')) {
        try {
            localStorage.removeItem(DB_KEY);
            alert('All local data has been deleted. The application will now reload.');
            location.reload();
        } catch(error) {
            console.error('Factory reset failed:', error);
            alert('Factory reset failed. Could not clear local storage.');
        }
    }
  }

  backupData(): void {
    const data = this.database();
    if (!data) {
      alert('No data to back up.');
      return;
    }
    try {
      const json = JSON.stringify(data, null, 2);
      const blob = new Blob([json], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      const date = new Date().toISOString().slice(0, 10);
      a.href = url;
      a.download = `future-world-backup-${date}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Backup failed:', error);
      alert('Could not create backup file.');
    }
  }

  importData(jsonString: string): boolean {
    try {
      const data: Database = JSON.parse(jsonString);
      // Basic validation to ensure the file is roughly the correct structure
      if (data && data.settings && Array.isArray(data.users)) {
        this.database.set(data);
        this._saveDatabase();
        return true;
      } else {
        return false;
      }
    } catch (error) {
      console.error('Import failed:', error);
      return false;
    }
  }
}

