import { Injectable, signal, computed } from '@angular/core';

export interface AdminSettings {
  masterPass: string;
  shopName: string;
}

export interface UserData {
  id: string;
  name:string;
  key: string;
  deviceId: string | null;
  createdAt: string;
  expiresAt: string | null;
}

export interface QuickSet {
  name: string;
  numbers: string[];
}

interface Database {
  settings: AdminSettings;
  users: UserData[];
  quickSets: QuickSet[];
}

const DB_KEY = 'fw_database';

@Injectable({
  providedIn: 'root',
})
export class DataService {
  private database = signal<Database | null>(null);

  adminSettings = computed(() => this.database()?.settings ?? null);
  allUsers = computed(() => this.database()?.users ?? []);
  quickSets = computed(() => this.database()?.quickSets ?? []);

  async initialize(): Promise<'login' | 'error'> {
    try {
      // Short delay to allow UI to show initializing state
      await new Promise(resolve => setTimeout(resolve, 50)); 

      const storedData = localStorage.getItem(DB_KEY);
      if (storedData) {
        const db = JSON.parse(storedData);
        // Ensure quickSets exists for backward compatibility
        if (!db.quickSets) {
          db.quickSets = [];
        }
        this.database.set(db);
      } else {
        // Create default initial state
        const defaultDb: Database = {
            settings: {
                shopName: 'အနာဂတ်ကမ္ဘာ',
                masterPass: 'MasterSaiYan'
            },
            users: [],
            quickSets: []
        };
        this.database.set(defaultDb);
        this._saveDatabase();
      }
      return 'login';
    } catch (error) {
      console.error("Failed to initialize data from localStorage:", error);
      this.database.set(null);
      return 'error';
    }
  }

  private _saveDatabase(): void {
    const currentData = this.database();
    if (!currentData) return;
    try {
      localStorage.setItem(DB_KEY, JSON.stringify(currentData));
    } catch (error) {
      console.error("Failed to save data to localStorage:", error);
      alert('Failed to save data. Your browser might be in private mode or storage is full.');
    }
  }

  updateAdminSettings(newSettings: Partial<AdminSettings>): void {
    this.database.update(db => {
        if (!db) return null;
        return { ...db, settings: { ...db.settings, ...newSettings } };
    });
    this._saveDatabase();
  }

  createNewUser(name: string, expiresAt: string | null): void {
    let key: string;
    let isUnique = false;

    // Ensure key is unique
    do {
      key = `KEY-${Math.random().toString(36).substring(2, 6).toUpperCase()}`;
      if (!this.allUsers().some(u => u.key === key)) {
        isUnique = true;
      }
    } while (!isUnique);

    const newUser: UserData = {
      id: crypto.randomUUID(),
      name,
      key,
      deviceId: null,
      createdAt: new Date().toISOString(),
      expiresAt
    };

    this.database.update(db => {
      if (!db) return null;
      return { ...db, users: [...db.users, newUser] };
    });

    this._saveDatabase();
  }

  deleteUser(userId: string): void {
    this.database.update(db => {
      if (!db) return null;
      return { ...db, users: db.users.filter(u => u.id !== userId) };
    });
    this._saveDatabase();
  }

  renewUserSubscription(userId: string, monthsToAdd: number): void {
    this.database.update(db => {
        if (!db) return null;

        const userIndex = db.users.findIndex(u => u.id === userId);
        if (userIndex === -1) {
            console.warn(`User with id ${userId} not found for renewal.`);
            return db;
        }

        const users = [...db.users];
        const user = { ...users[userIndex] };

        const now = new Date();
        // Determine the base date for renewal: either the current expiry date (if it's in the future) or today.
        const baseDate = user.expiresAt && new Date(user.expiresAt) > now ? new Date(user.expiresAt) : now;

        const newExpiryDate = new Date(baseDate);
        newExpiryDate.setMonth(newExpiryDate.getMonth() + monthsToAdd);

        user.expiresAt = newExpiryDate.toISOString();
        users[userIndex] = user;

        return { ...db, users };
    });
    this._saveDatabase();
  }

  linkDeviceToUser(userId: string, deviceId: string): void {
    this.database.update(db => {
      if (!db) return null;
      const users = [...db.users];
      const userIndex = users.findIndex(u => u.id === userId);
      if (userIndex !== -1) {
        users[userIndex] = { ...users[userIndex], deviceId };
      }
      return { ...db, users };
    });
    this._saveDatabase();
  }

  resetUserDevice(userId: string): void {
    this.database.update(db => {
      if (!db) return null;
      const users = [...db.users];
      const userIndex = users.findIndex(u => u.id === userId);
      if (userIndex !== -1) {
        users[userIndex] = { ...users[userIndex], deviceId: null };
      }
      return { ...db, users };
    });
    this._saveDatabase();
  }

  addQuickSet(quickSet: QuickSet): void {
    this.database.update(db => {
      if (!db) return null;
      // Prevent duplicate names
      const existing = db.quickSets.find(qs => qs.name === quickSet.name);
      if (existing) {
        alert('A Quick Set with this name already exists.');
        return db;
      }
      return { ...db, quickSets: [...db.quickSets, quickSet] };
    });
    this._saveDatabase();
  }

  deleteQuickSet(setName: string): void {
    this.database.update(db => {
      if (!db) return null;
      return { ...db, quickSets: db.quickSets.filter(qs => qs.name !== setName) };
    });
    this._saveDatabase();
  }


  factoryReset(): void {
    if (confirm('Are you sure you want to delete ALL users and settings? This action cannot be undone. It is recommended to backup data first.')) {
        try {
            localStorage.removeItem(DB_KEY);
            localStorage.removeItem('fw_device_id');
            alert('All local data has been deleted. The application will now reload.');
            location.reload();
        } catch(error) {
            console.error('Factory reset failed:', error);
            alert('Factory reset failed. Could not clear local storage.');
        }
    }
  }

  backupData(): void {
    const data = this.database();
    if (!data) {
      alert('No data to back up.');
      return;
    }
    try {
      const json = JSON.stringify(data, null, 2);
      const blob = new Blob([json], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      const date = new Date().toISOString().slice(0, 10);
      a.href = url;
      a.download = `future-world-backup-${date}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Backup failed:', error);
      alert('Could not create backup file.');
    }
  }

  importData(jsonString: string): boolean {
    try {
      const data: Database = JSON.parse(jsonString);
      // Basic validation to ensure the file is roughly the correct structure
      if (data && data.settings && Array.isArray(data.users)) {
        if (!data.quickSets) { // Ensure quicksets exists for older backups
          data.quickSets = [];
        }
        this.database.set(data);
        this._saveDatabase();
        return true;
      } else {
        return false;
      }
    } catch (error) {
      console.error('Import failed:', error);
      return false;
    }
  }
}

import { Component, ChangeDetectionStrategy, signal, inject, effect, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService } from './services/data.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'initializing' | 'error' | 'login' | 'app';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
  ],
})
export class AppComponent implements OnInit {
  private dataService = inject(DataService);
  private titleService = inject(Title);

  appState = signal<AppState>('initializing');
  isAdmin = signal(false);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  users = this.dataService.allUsers;

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });
  }

  async ngOnInit() {
    this.initializeApp();
  }

  async initializeApp() {
    this.appState.set('initializing');
    const initState = await this.dataService.initialize();
    this.appState.set(initState);
  }

  retry() {
    location.reload();
  }

  private getDeviceId(): string {
    let deviceId = localStorage.getItem('fw_device_id');
    if (!deviceId) {
      deviceId = crypto.randomUUID();
      localStorage.setItem('fw_device_id', deviceId);
    }
    return deviceId;
  }

  handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const input = loginInput.trim().toUpperCase();
    const settings = this.adminSettings();
    const users = this.users();

    if (!settings) {
      this.loginError.set('Application data could not be loaded.');
      this.isLoggingIn.set(false);
      return;
    }

    // Admin Login
    if (input === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);
      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    // User Login
    const user = users.find(u => u.key.toUpperCase() === input);

    if (!user) {
      this.loginError.set('ကုဒ်မှားနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Check for expiration
    if (user.expiresAt && new Date(user.expiresAt) < new Date()) {
      this.loginError.set('Key သက်တမ်းကုန်နေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // Device ID Check
    const deviceId = this.getDeviceId();
    if (user.deviceId && user.deviceId !== deviceId) {
      this.loginError.set('ဤကုဒ်သည် အခြားစက်တွင် အသုံးပြုနေပါသည်');
      this.isLoggingIn.set(false);
      return;
    }

    // If first login on any device, link the device
    if (!user.deviceId) {
      this.dataService.linkDeviceToUser(user.id, deviceId);
    }


    // Success
    this.isAdmin.set(false);
    this.appState.set('app');
    this.activeTab.set('calc');
    this.isLoggingIn.set(false);
  }

  handleLogout() {
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(null);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  clearLoginError() {
      this.loginError.set(null);
  }
}

import { Component, ChangeDetectionStrategy, inject, signal, OnInit, computed, ViewChild, ElementRef } from '@angular/core';
import { DataService, UserData } from '../../services/data.service';
import { CommonModule } from '@angular/common';
import { Trash2IconComponent } from '../icons/trash2-icon.component';
import { SettingsIconComponent } from '../icons/settings-icon.component';
import { UsersIconComponent } from '../icons/users-icon.component';
import { ShareIconComponent } from '../icons/share-icon.component';
import { CheckIconComponent } from '../icons/check-icon.component';
import { DownloadIconComponent } from '../icons/download-icon.component';
import { UploadIconComponent } from '../icons/upload-icon.component';
import { PlusIconComponent } from '../icons/plus-icon.component';
import { DeviceOffIconComponent } from '../icons/device-off-icon.component';

@Component({
  selector: 'app-admin-panel',
  templateUrl: './admin-panel.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, Trash2IconComponent, SettingsIconComponent, UsersIconComponent, ShareIconComponent, CheckIconComponent, DownloadIconComponent, UploadIconComponent, PlusIconComponent, DeviceOffIconComponent]
})
export class AdminPanelComponent implements OnInit {
  private dataService = inject(DataService);

  @ViewChild('restoreInput') restoreInput!: ElementRef<HTMLInputElement>;

  allUsers = this.dataService.allUsers;
  adminSettings = this.dataService.adminSettings;

  sortedUsers = computed(() => {
    const users = this.allUsers() ?? [];
    return users.slice().sort((a: UserData, b: UserData) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  });

  // User creation state
  name = signal('');
  subscriptionDuration = signal<1 | 3 | 6 | 'none'>(1);

  // New state for tabs and settings
  activeAdminTab = signal<'users' | 'settings'>('users');
  shopNameInput = signal('');
  masterPassInput = signal('');
  settingsSaved = signal(false);
  copiedKeyId = signal<string | null>(null);

  ngOnInit() {
    const currentSettings = this.adminSettings();
    if (currentSettings) {
      this.shopNameInput.set(currentSettings.shopName);
      this.masterPassInput.set(currentSettings.masterPass);
    }
  }

  createKey() {
    if (!this.name().trim()) return;

    let expiryValue: string | null = null;
    const duration = this.subscriptionDuration();

    if (duration !== 'none') {
        const expiry = new Date();
        expiry.setMonth(expiry.getMonth() + duration);
        expiryValue = expiry.toISOString();
    }

    this.dataService.createNewUser(this.name().trim(), expiryValue);
    this.name.set('');
  }

  deleteUser(userId: string) {
    if (confirm('Are you sure you want to delete this user?')) {
        this.dataService.deleteUser(userId);
    }
  }

  renewUser(user: UserData) {
    if(confirm(`Renew subscription for ${user.name} by 1 month?`)) {
        this.dataService.renewUserSubscription(user.id, 1);
    }
  }

  resetDevice(user: UserData) {
    if (confirm(`Are you sure you want to reset the device lock for ${user.name}? They will be able to log in from a new device.`)) {
      this.dataService.resetUserDevice(user.id);
    }
  }

  getExpiryStatus(user: UserData): { text: string; colorClass: string } {
    if (!user.expiresAt) {
      return { text: 'Never', colorClass: 'text-green-500' };
    }
    const expiryDate = new Date(user.expiresAt);
    const now = new Date();
    // Reset time part to compare dates only
    expiryDate.setHours(0, 0, 0, 0);
    now.setHours(0, 0, 0, 0);

    const diffTime = expiryDate.getTime() - now.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) {
      return { text: `Expired`, colorClass: 'text-rose-500' };
    }
    if (diffDays === 0) {
       return { text: `Expires today`, colorClass: 'text-amber-500' };
    }
    if (diffDays <= 7) {
      return { text: `in ${diffDays} days`, colorClass: 'text-amber-500' };
    }
    return { text: `in ${diffDays} days`, colorClass: 'text-slate-400' };
  }

  saveSettings() {
    const shopName = this.shopNameInput().trim();
    const masterPass = this.masterPassInput().trim();

    if (!shopName || !masterPass) {
      alert('Shop name and master password cannot be empty.');
      return;
    }

    this.dataService.updateAdminSettings({ shopName, masterPass });
    this.settingsSaved.set(true);
    setTimeout(() => this.settingsSaved.set(false), 2000);
  }

  async shareKey(user: UserData) {
    const expiryText = user.expiresAt ? new Date(user.expiresAt).toLocaleDateString('en-GB') : 'Never';
    const userId = user.id.substring(0, 8).toUpperCase();
    const textToCopy = `အမည်: ${user.name}\nUser ID: ${userId}\nကုဒ် (Key): ${user.key}\nသက်တမ်းကုန်ဆုံးရက်: ${expiryText}`;
    try {
        await navigator.clipboard.writeText(textToCopy);
        this.copiedKeyId.set(user.id);
        setTimeout(() => this.copiedKeyId.set(null), 2000);
    } catch (err) {
        console.error('Failed to copy key: ', err);
        alert('Failed to copy key.');
    }
  }

  factoryReset() {
    this.dataService.factoryReset();
  }

  backupData() {
    this.dataService.backupData();
  }

  triggerRestore() {
    if (confirm('This will overwrite all current data with the backup file. Are you sure you want to proceed?')) {
      this.restoreInput.nativeElement.click();
    }
  }

  handleRestoreFile(event: Event) {
    const input = event.target as HTMLInputElement;
    if (!input.files || input.files.length === 0) {
      return;
    }

    const file = input.files[0];
    const reader = new FileReader();

    reader.onload = (e) => {
      try {
        const jsonString = e.target?.result as string;
        const success = this.dataService.importData(jsonString);
        if (success) {
          alert('Data restored successfully! The application will now reload.');
          location.reload();
        } else {
          alert('Restore failed. The backup file is invalid or corrupted.');
        }
      } catch (error) {
        console.error('Error reading or parsing restore file:', error);
        alert('Restore failed. Could not read the file.');
      }
    };

    reader.onerror = () => {
        alert('Error reading file.');
    };

    reader.readAsText(file);
    input.value = ''; // Reset file input
  }
}

